INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$What does the vidIQ Max plan cost?$q$, $q$Max is $39/month billed annually and includes 6,000 monthly AI credits.$q$, 1);
