INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$overview$q$, $q$What is vidIQ?$q$, 2, ARRAY[$q$vidIQ is a YouTube and Instagram growth platform that provides AI-powered video optimization — including titles, tags, and thumbnails — plus analytics and creator coaching to help video creators grow views and subscribers.$q$, $q$The platform is available as a browser extension and mobile app for iOS and Android, with a free tier and paid Max and Enterprise plans offering higher AI credit limits and more advanced coaching.$q$]::text[], 0);
