INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Channel benchmarking$q$, $q$Compares a channel's performance against similarly sized channels to spot gaps.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Actionable recommendations$q$, $q$Provides specific improvement suggestions based on comparative data.$q$, 2);
