INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$What does Morningfame do?$q$, $q$It provides YouTube analytics and search optimization guidance, including benchmarking against similarly sized channels.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Does Morningfame offer a demo?$q$, $q$Yes, a demo report is available via a link on the site.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Does Morningfame support platforms other than YouTube?$q$, $q$The official site only describes YouTube-focused features.$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Video SEO improvement$q$, $q$Optimize video titles, descriptions, and tags to rank in YouTube Search.$q$, $q$YouTube creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Peer channel benchmarking$q$, $q$Compare channel performance against similarly sized YouTube channels to find growth gaps.$q$, $q$Growing YouTube channels$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$overview$q$, $q$What is Morningfame?$q$, 2, ARRAY[$q$Morningfame is a YouTube analytics platform that helps creators optimize videos for YouTube Search and benchmarks their channel against similarly sized peers to identify performance gaps.$q$, $q$It highlights which videos outperformed or underperformed relative to a creator's other content, helping creators replicate what worked.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$who-its-for$q$, $q$Who Morningfame is for$q$, 2, ARRAY[$q$Morningfame is aimed at YouTube creators of all sizes who want data-driven guidance on video search optimization and want to see how their channel compares to similar peers.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20893471-10cd-4caf-9754-dcf19b7c21a8', $q$Multi-platform tracking$q$, $q$Tracks statistics for YouTube, Twitch, Instagram, Twitter/X, and TikTok accounts.$q$, 0);
