INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Automated cross-posting$q$, $q$Detects new content on a source platform and automatically publishes it to connected destination platforms.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Auto-resize for each platform$q$, $q$Reformats video dimensions to match the requirements of each destination platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Watermark removal$q$, $q$Removes source-platform watermarks before republishing content elsewhere.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Broad platform connections$q$, $q$Connects to YouTube, TikTok, Instagram, Facebook, Snapchat, Pinterest, LinkedIn, X, Twitch, Google Drive, and Dropbox, among others.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Long-to-short clipping$q$, $q$Turns long-form video into shorter clips for distribution.$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Connects to a wide range of destination platforms (15+) from one dashboard$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Removes manual re-uploading and re-formatting work for creators posting to multiple networks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Offers a 14-day free trial with no credit card required$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Tiered plans scale account-connection limits for agencies managing multiple clients$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$No permanently free plan — paid subscription required after the trial or limited free video allowance$q$, 0);
