INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Focused on repurposing/distribution rather than original content creation or editing$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Does Repurpose.io offer a free trial?$q$, $q$Yes, it offers a 14-day free trial with no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$How much does Repurpose.io cost?$q$, $q$Plans start at $35/month (Starter) and go up to $179/month (Agency) on monthly billing, with about 17% savings on annual billing.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$What platforms can Repurpose.io publish to?$q$, $q$It connects to Instagram, TikTok, YouTube, Facebook, Pinterest, LinkedIn, Snapchat, X, and other platforms.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Does Repurpose.io detect new content automatically?$q$, $q$Yes, it monitors the source platform and republishes new content without manual action once set up.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Cross-platform video distribution$q$, $q$Creators post once to a primary platform and have it automatically reformatted and published elsewhere.$q$, $q$Solo creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Multi-client repurposing$q$, $q$Agencies manage repurposing and distribution across many client accounts under one plan.$q$, $q$Social media agencies$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Starter$q$, $q$$35/month ($349/year billed annually)$q$, $q$monthly$q$, $q$["Up to 3 account connections per social network","Up to 5,000 published videos/month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Pro$q$, $q$$79/month ($790/year billed annually)$q$, $q$monthly$q$, $q$["Up to 10 account connections per social network","Unlimited monthly publishing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Agency$q$, $q$$179/month ($1,790/year billed annually)$q$, $q$monthly$q$, $q$["Up to 25 account connections per social network","Unlimited monthly publishing"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$overview$q$, $q$What is Repurpose.io?$q$, 2, ARRAY[$q$Repurpose.io is an automated content repurposing and distribution platform for video and audio creators.$q$, $q$It watches a source platform for new uploads, then automatically resizes, removes watermarks, and republishes the content across connected destinations like YouTube, TikTok, Instagram, and Facebook.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$who-its-for$q$, $q$Who Repurpose.io is for$q$, 2, ARRAY[$q$It suits solo creators who want to be on multiple platforms without manual re-uploading, as well as agencies that repurpose content across many client accounts at once.$q$]::text[], 1);
