INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('366134f6-a5b9-48d8-883a-e54211d7dd34', $q$Does Sunsama have a free trial?$q$, $q$Yes, a 14-day free trial with no credit card required and full feature access.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('366134f6-a5b9-48d8-883a-e54211d7dd34', $q$How much does Sunsama cost?$q$, $q$The Pro plan is $22/month billed monthly or $17/month billed yearly, on a per-person basis.$q$, 1);
