INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('366134f6-a5b9-48d8-883a-e54211d7dd34', $q$Is Sunsama priced per person for teams?$q$, $q$Yes, each teammate added to a workspace is billed individually and the total updates automatically.$q$, 3);
