INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('366134f6-a5b9-48d8-883a-e54211d7dd34', $q$Distraction-free deep work$q$, $q$Users rely on Focus Mode and app muting to protect blocks of concentrated work time.$q$, $q$Remote workers$q$, 1);
