INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Business/Enterprise features like access control and audit logs require the higher-priced team tiers$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Is Routine free?$q$, $q$Yes, Routine has a free forever plan with tasks, calendar, notes, and a basic AI assistant; paid tiers add more integrations, databases, and AI credits.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$How much do paid Routine plans cost?$q$, $q$Personal is $5/month, Professional is $10/month, and Business is $15/seat/month; Enterprise is custom-priced.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Does Routine support AI meeting notes?$q$, $q$Yes, AI meeting notes and AI agents/automations are included from the Professional plan upward.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$What platforms is Routine available on?$q$, $q$Routine is available on macOS, Windows, Linux, web, iOS, and Android.$q$, 3);
