INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$who-its-for$q$, $q$Who Routine is for$q$, 2, ARRAY[$q$Routine suits individuals and small teams who want one app for tasks, calendar, and notes, with room to grow into AI automation and custom databases as needs expand.$q$]::text[], 1);
