INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Calendar consolidation$q$, $q$Combines calendars from Google, Outlook, Apple, Fastmail, and others into one view.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Task integrations$q$, $q$Pulls in tasks from Notion, ClickUp, Linear, and Todoist.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Calendar automations$q$, $q$Automatically blocks travel time and buffer time around meetings.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Scheduling links$q$, $q$Lets users share personalized booking links so others can schedule time with them.$q$, 4);
