INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$AI planner is a paid-tier feature, not available on a free tier$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Does Morgen have a free trial?$q$, $q$Yes, a 14-day free trial with full access and no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$How much does Morgen cost?$q$, $q$Pro is $30/month billed monthly or $15/month billed annually; Team is $25/seat/month monthly or $10/seat/month annually (2-seat minimum).$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$What does Morgen's AI Planner do?$q$, $q$It generates a prioritized daily plan and re-prioritizes it if new conflicts arise.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$What calendars and tools does Morgen integrate with?$q$, $q$Google, Outlook, Apple, and Fastmail calendars, plus tasks from Notion, ClickUp, Linear, and Todoist.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Unified calendar view$q$, $q$People with multiple calendar accounts consolidate them into a single AI-planned schedule.$q$, $q$Professionals with multiple calendars$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Team meeting coordination$q$, $q$Teams check colleague availability and share booking links to schedule meetings faster.$q$, $q$Small teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Pro (monthly)$q$, $q$$30/month$q$, $q$monthly$q$, $q$["AI Planner time blocking","Unlimited calendar/task integrations","Calendar automations","Booking page & scheduling links","Cross-platform apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Pro (yearly)$q$, $q$$15/month billed annually$q$, $q$annual$q$, $q$["All Pro monthly features","Access to new features as Morgen evolves"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Team (monthly)$q$, $q$$25/seat/month (2-seat minimum)$q$, $q$monthly$q$, $q$["AI Planner time blocking","Unlimited integrations","Calendar automations","Booking/scheduling links"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Team (yearly)$q$, $q$$10/seat/month billed annually (2-seat minimum)$q$, $q$annual$q$, $q$["All Team monthly features","Cancel-anytime flexibility"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$overview$q$, $q$What is Morgen?$q$, 2, ARRAY[$q$Morgen is a calendar and task management app, built in Switzerland, that consolidates calendars from multiple providers alongside tasks from tools like Notion, ClickUp, Linear, and Todoist.$q$, $q$Its AI Planner generates a daily schedule that users can preview, adjust, and confirm, re-prioritizing automatically when conflicts arise.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$who-its-for$q$, $q$Who Morgen is for$q$, 2, ARRAY[$q$Morgen suits professionals juggling calendars across multiple accounts and task tools who want one AI-assisted view of their day, as well as small teams coordinating meeting availability.$q$]::text[], 1);
