INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$Bot-free meeting recording$q$, $q$Records meetings across Zoom, Google Meet, Microsoft Teams, Slack Huddle, Webex, and other platforms without a bot joining the call.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$Multi-language transcription$q$, $q$Supports 17 languages with speaker-label separation and 82 additional languages without speaker labeling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$AI summaries & action items$q$, $q$Generates meeting summaries with business context and turns them into automated action items.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$AI chat assistant$q$, $q$A contextual AI assistant that can draft emails, create or update meetings, rewrite summaries, and create mind maps.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$Calendar & task management$q$, $q$Combines meeting action items with external to-dos and AI-powered scheduling.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$CRM/ATS integrations$q$, $q$Connects with HubSpot, Notion, Slack, Linear, Pipedrive, Personio, Ashby, and Greenhouse.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$Records and transcribes meetings without requiring a bot to join the call$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$Transcribes 17 languages with speaker labeling, plus 82 more without$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$AI chat assistant can take actions like drafting emails or rescheduling meetings, not just summarize$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$Integrates with common CRM and ATS tools (HubSpot, Pipedrive, Ashby, Greenhouse)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$Exact pricing is not published in plain text on the official pricing page (only plan names and feature comparisons)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$Business-tier features like a custom recording bot and audit logs are gated behind the higher-priced plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$Available only on macOS, Windows, and iOS — no confirmed Android or Linux app$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$Does Amie need a bot to join meetings?$q$, $q$No, Amie records meetings without a separate bot participant joining the call.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$What languages does Amie transcribe?$q$, $q$It transcribes 17 languages with speaker labeling and 82 additional languages without speaker labeling.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$What plans does Amie offer?$q$, $q$Amie offers Pro and Business plans, billed monthly or yearly (with a yearly discount); specific prices are not listed in plain text on the pricing page.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$What does Amie's AI assistant do?$q$, $q$It can draft emails, create or update meetings, rewrite summaries, and create mind maps based on meeting context.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$Automated meeting follow-up$q$, $q$Professionals use Amie to turn meeting discussions directly into action items and CRM updates.$q$, $q$Sales and account teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$Unified calendar and notes$q$, $q$Users replace separate calendar, notes, and task apps with one AI-assisted workspace.$q$, $q$Individual professionals$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c847d46-b23f-437e-8dd9-7f034b7c3c9f', $q$overview$q$, $q$What is Amie?$q$, 2, ARRAY[$q$Amie is an AI-powered meeting notes and calendar app that records and transcribes calls across platforms like Zoom, Google Meet, and Microsoft Teams without requiring a bot to join.$q$, $q$It generates AI summaries and action items from meetings, and includes a contextual AI chat assistant that can draft emails, reschedule meetings, and manage tasks.$q$]::text[], 0);
