INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Grammarly writing assistance$q$, $q$AI writing help for rewriting, translating, and detecting AI-generated text, included via the Grammarly integration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$CRM & data integrations$q$, $q$Connects with HubSpot, Salesforce, Pipedrive, Jira, GitHub, and Figma on higher-tier plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Enterprise security controls$q$, $q$SAML SSO, custom roles, and permissions available on the Enterprise plan.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Free tier available with AI chat, Grammarly writing help, and Docs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Business tier bundles the original Superhuman Mail experience with AI writing and CRM integrations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Works across 800+ tools and is compatible with Claude, ChatGPT, and Cursor$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Enterprise plan adds SAML SSO and advanced admin controls for larger organizations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Superhuman Mail itself is only included on the Business plan, not the Free or Pro tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Enterprise pricing requires contacting sales rather than transparent self-serve pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Pricing shown on the official site is listed in euros, so USD cost may vary by region$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Is Superhuman free?$q$, $q$There is a Free plan with AI chat, Grammarly, and Docs, but it does not include Superhuman Mail.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$How much does Superhuman cost?$q$, $q$Pro is €12/member/month billed annually (€15/month billed monthly); Business, which includes Mail, is €33/member/month annually (€40/month monthly); Enterprise is custom-priced.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Is Superhuman still a separate company?$q$, $q$Superhuman was acquired by Grammarly, and its products (Mail, Docs, Go) are now offered as part of the Superhuman/Grammarly suite under the Superhuman name.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$What is Superhuman Go?$q$, $q$Go is an AI assistant that works across connected apps to provide proactive, cross-application help.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Fast email management$q$, $q$Professionals use Superhuman Mail on the Business plan to move through email faster.$q$, $q$Busy professionals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$AI-assisted writing and docs$q$, $q$Teams use Grammarly-powered writing help and collaborative Docs for shared projects.$q$, $q$Business teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Free$q$, $q$€0$q$, NULL, $q$["AI chat across apps","Grammarly writing assistance","Collaborative Docs"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Pro$q$, $q$€12/member/month billed annually (€15/month billed monthly)$q$, $q$monthly$q$, $q$["Everything in Free","Unlimited paragraph rewrites and translations","AI-generated text detection","Brand voice customization","Custom domain publishing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Business$q$, $q$€33/member/month billed annually (€40/month billed monthly)$q$, $q$monthly$q$, $q$["Everything in Pro","Superhuman Mail","CRM integrations (HubSpot, Salesforce, Pipedrive)","Unlimited automations","Data connectors (Jira, GitHub, Figma)"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$Enterprise$q$, $q$Custom pricing$q$, NULL, $q$["Analytics and reporting","SAML SSO","Custom roles and permissions","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$overview$q$, $q$What is Superhuman?$q$, 2, ARRAY[$q$Superhuman is a productivity suite built around fast email (Superhuman Mail), collaborative documents (Docs), and a cross-app AI assistant (Go), now offered under Grammarly following its acquisition of Superhuman.$q$, $q$Plans range from a free tier with AI chat and Docs up to a Business tier that adds Superhuman Mail and CRM integrations, with a custom-priced Enterprise tier for larger organizations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('331db11d-c5e0-4d89-b61b-3caeaaa512ad', $q$who-its-for$q$, $q$Who Superhuman is for$q$, 2, ARRAY[$q$Superhuman targets professionals who want faster email plus AI-assisted writing and workflows, and businesses that need CRM-connected automation and admin controls at the higher tiers.$q$]::text[], 1);
