INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Is there a free version of Missive?$q$, $q$No, Missive offers a 30-day free trial rather than a permanent free plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$What platforms does Missive support?$q$, $q$macOS, Windows, iOS, iPadOS, Android, and a web app.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$How much does Missive cost?$q$, $q$Starter is $14/user/month, Productive is $24/user/month, and Business is $36/user/month, each with a yearly discount option.$q$, 2);
