INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Business$q$, $q$$36/user/month$q$, $q$monthly$q$, $q$["Unlimited users","SAML SSO","IP restriction","Advanced analytics & reporting","Personalized onboarding"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$overview$q$, $q$What is Missive?$q$, 2, ARRAY[$q$Missive is a collaborative inbox built for teams that run their work through email. It lets teammates see the same inbox, comment internally, and turn messages into tasks without changing how they email externally.$q$, $q$It's available as native apps for macOS, Windows, iOS, iPadOS, and Android, alongside a web app, and includes an AI assistant that can use Anthropic, OpenAI, or Gemini models.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$who-its-for$q$, $q$Who Missive is for$q$, 2, ARRAY[$q$Small teams handling shared support, sales, or operations inboxes use Missive to avoid duplicate replies and track who owns what conversation.$q$]::text[], 1);
