INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5bc5e5ac-f3fd-4a2a-9044-5288a6b4cd79', $q$What does Spike's AI do?$q$, $q$It provides smart inbox sorting, AI summaries of unread email, and contextual draft replies.$q$, 2);
