INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5bc5e5ac-f3fd-4a2a-9044-5288a6b4cd79', $q$overview$q$, $q$What is Spike?$q$, 2, ARRAY[$q$Spike is an email client that reformats messages as chat-style conversations and adds AI summaries and drafting to existing Gmail, Outlook, and other inboxes.$q$, $q$Beyond email, it bundles team chat, collaborative docs, tasks, and video calls, and is available on iOS, Android, Mac, Windows, and the web.$q$]::text[], 0);
