INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e7803795-ad28-4f0d-b4c7-34871b2be738', $q$Is Twist free?$q$, $q$Yes, Twist has a free plan limited to 1 month of message history and 5 integrations.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e7803795-ad28-4f0d-b4c7-34871b2be738', $q$How much is Twist's paid plan?$q$, $q$The Unlimited plan is €6 per user/month and includes full history, unlimited integrations, and unlimited file storage.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e7803795-ad28-4f0d-b4c7-34871b2be738', $q$Who makes Twist?$q$, $q$Twist is made by Doist Inc., the company behind Todoist.$q$, 2);
