INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7803795-ad28-4f0d-b4c7-34871b2be738', $q$Distributed team communication$q$, $q$Remote and async teams use topic-based channels to keep project discussion organized without constant real-time chat.$q$, $q$Remote/distributed teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7803795-ad28-4f0d-b4c7-34871b2be738', $q$Reducing chat interruptions$q$, $q$Teams that find real-time chat disruptive use Twist's threading and smart notifications to enable deep work.$q$, $q$Product and engineering teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e7803795-ad28-4f0d-b4c7-34871b2be738', $q$Free$q$, $q$€0/user/month$q$, NULL, $q$["1 month of comments/messages history","Up to 5 integrations","5GB file storage","Up to 500 internal member accounts","Standard support"]$q$::jsonb, 0);
