INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7803795-ad28-4f0d-b4c7-34871b2be738', $q$overview$q$, $q$What is Twist?$q$, 2, ARRAY[$q$Twist is a team messaging app from Doist that organizes conversations into threads and topic-based channels instead of a single real-time feed, aiming to reduce interruptions for distributed teams.$q$, $q$It's available on web, iOS, Android, Mac, and Windows, with integrations for Google Drive, GitHub, Zoom, Todoist, Zapier, Asana, and Calendly.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7803795-ad28-4f0d-b4c7-34871b2be738', $q$who-its-for$q$, $q$Who Twist is for$q$, 2, ARRAY[$q$Remote and distributed teams that want organized, async-first discussion instead of constant real-time chat notifications.$q$]::text[], 1);
