INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$overview$q$, $q$What is Nuclino?$q$, 2, ARRAY[$q$Nuclino is a collaborative workspace that brings docs, knowledge, and lightweight project tracking together, with real-time editing and instant search.$q$, $q$It includes an AI assistant, Sidekick, on its Business plan, and is used by teams including NASA, Ubisoft, and MIT according to the company's site.$q$]::text[], 0);
