INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Knowledge Agents$q$, $q$Automated agents verify and improve knowledge, flagging conflicting versions, duplicates, and gaps.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$AI search and chat$q$, $q$Permission-aware AI search and chat surface cited answers grounded in governed company knowledge.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Workflow integrations$q$, $q$Integrates with Slack, Microsoft Teams, Claude, Chrome, Cursor, and MCP so answers appear where people already work.$q$, 2);
