INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$No self-serve free plan advertised on the site$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Is Guru's pricing public?$q$, $q$No, Guru uses custom pricing scoped during a conversation with its sales team based on organization scale and AI usage.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Does Guru work with AI assistants like Claude or Copilot?$q$, $q$Yes, Guru delivers governed, cited knowledge into tools such as Claude, Microsoft Copilot, and other AI assistants via integrations and MCP.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Is there a nonprofit discount?$q$, $q$Yes, Guru offers reduced pricing for eligible 501(c)(3) nonprofit organizations through its Guru for Good program.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Is Guru HIPAA compliant?$q$, $q$Guru states it is HIPAA-ready and holds SOC 2 Type II certification.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Governed knowledge for AI assistants$q$, $q$Feed verified, permission-scoped company knowledge into AI chat tools so answers are accurate and cited.$q$, $q$Enterprise IT and knowledge teams$q$, 0);
