INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$who-its-for$q$, $q$Who Guru is for$q$, 2, ARRAY[$q$Guru targets enterprise organizations across industries such as technology, healthcare, finance, and retail that need governed knowledge for HR, support, sales, engineering, and other teams.$q$]::text[], 1);
