INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Is Document360 pricing public?$q$, $q$No, Document360 uses custom pricing based on team accounts, workspaces, languages, security needs, and AI usage; customers get a quote after a short questionnaire and sales conversation.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Does Document360 offer a free trial?$q$, $q$Yes, it offers a 14-day free trial with access to all features before requiring a plan selection.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$What plan tiers does Document360 offer?$q$, $q$Professional, Business, and Enterprise are the plan tiers customers can subscribe to after the trial.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Can Document360 connect to AI assistants like ChatGPT or Claude?$q$, $q$Yes, via its MCP Server integration, Document360 connects its knowledge base to ChatGPT, Claude, and Copilot.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$Public product documentation$q$, $q$Publish searchable, SEO-customizable docs with a custom domain for end users.$q$, $q$Technical writers and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$AI-assisted self-service support$q$, $q$Deflect support tickets using an AI chatbot that answers from existing docs, tickets, and files.$q$, $q$Customer support teams$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$overview$q$, $q$What is Document360?$q$, 2, ARRAY[$q$Document360 is an AI-powered knowledge base platform that lets teams create, manage, and publish documentation, combining traditional authoring tools with conversational AI search, an AI chatbot, and an AI writing agent.$q$, $q$It offers 100+ authoring, search, and security features, plus 60+ integrations with tools like Slack, Zendesk, Salesforce, and GitHub.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c7727b97-e9ad-4f83-862e-ffc1b256280f', $q$who-its-for$q$, $q$Who Document360 is for$q$, 2, ARRAY[$q$The platform serves support teams, technical writers, product managers, and developers across SaaS, healthcare, finance, manufacturing, and retail who need both public documentation and internal knowledge bases.$q$]::text[], 1);
