INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2632cf96-67cf-472b-ba2a-9e7b8ce56e16', $q$Multi-language support$q$, $q$Localization and AI article translation across 50+ languages.$q$, 3);
