INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2632cf96-67cf-472b-ba2a-9e7b8ce56e16', $q$Headquarters city and company size are not disclosed on the site$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2632cf96-67cf-472b-ba2a-9e7b8ce56e16', $q$How much does Helpjuice cost?$q$, $q$Plans start at $249/month for the Knowledge Base plan (30 users, no AI Suite), with AI-enabled plans at $449/month and $799/month for unlimited users.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2632cf96-67cf-472b-ba2a-9e7b8ce56e16', $q$Does Helpjuice offer a free trial?$q$, $q$Yes, a 14-day free trial is available with no credit card required.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2632cf96-67cf-472b-ba2a-9e7b8ce56e16', $q$Does Helpjuice include AI features?$q$, $q$The AI-Knowledge Base plan ($449/month) and Unlimited AI-Knowledge Base plan ($799/month) include the full AI Suite: AI Writer, AI Search, AI Chatbot, and a Tutorial Builder.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2632cf96-67cf-472b-ba2a-9e7b8ce56e16', $q$When was Helpjuice founded?$q$, $q$Helpjuice was founded in 2011.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2632cf96-67cf-472b-ba2a-9e7b8ce56e16', $q$Internal knowledge base$q$, $q$Centralize company knowledge to speed up onboarding and reduce repetitive questions.$q$, $q$Operations and HR teams$q$, 0);
