INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2632cf96-67cf-472b-ba2a-9e7b8ce56e16', $q$AI-Knowledge Base$q$, $q$$449/month$q$, $q$monthly$q$, $q$["100 users included","24GB storage","SSO","Full AI Suite: AI Writer, AI Search, AI Chatbot, Chrome Extension, Tutorial Builder"]$q$::jsonb, 1);
