INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2632cf96-67cf-472b-ba2a-9e7b8ce56e16', $q$overview$q$, $q$What is Helpjuice?$q$, 2, ARRAY[$q$Helpjuice is a knowledge base platform, founded in 2011, that centralizes organizational information into searchable documentation with AI-powered writing, search, and a chatbot layered on top.$q$, $q$Its AI Suite can draft articles directly from Slack messages, support tickets, or emails, and its search is designed to understand context rather than requiring exact keyword matches.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2632cf96-67cf-472b-ba2a-9e7b8ce56e16', $q$who-its-for$q$, $q$Who Helpjuice is for$q$, 2, ARRAY[$q$Helpjuice serves support and customer service teams, operations and HR functions, and SaaS or product-led companies that need to scale documentation quickly.$q$]::text[], 1);
