INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0eab6628-ac5f-4215-9f5b-92be748bae51', $q$How much does Archbee cost?$q$, $q$Plans start at $80/month for Growing, $350/month for Scaling, and custom pricing for Enterprise.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0eab6628-ac5f-4215-9f5b-92be748bae51', $q$Does Archbee offer a free trial?$q$, $q$Yes, a 14-day free trial with no credit card required and unlimited readers.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0eab6628-ac5f-4215-9f5b-92be748bae51', $q$Does Archbee have a free plan?$q$, $q$Yes, an Open Source program provides a free Growing plan for qualifying open-source projects.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0eab6628-ac5f-4215-9f5b-92be748bae51', $q$What platforms does Archbee support?$q$, $q$Archbee is web-based and also offers native apps for macOS, Windows, and Linux.$q$, 3);
