INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0eab6628-ac5f-4215-9f5b-92be748bae51', $q$Growing$q$, $q$$80/month$q$, $q$monthly$q$, $q$["Unlimited readers","Unlimited project spaces","Public/private portals","Custom domain & branding","Custom JavaScript","Password protection","GitHub integration","API documentation"]$q$::jsonb, 0);
