INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$overview$q$, $q$What is ClickHelp?$q$, 2, ARRAY[$q$ClickHelp is a cloud-based documentation platform for authoring, hosting, and delivering technical documentation from a single portal, supporting user guides, knowledge bases, API docs, and training materials.$q$, $q$It supports migration from legacy formats like MS Word, OpenOffice, HTML, Web Help, and CHM, and offers an optional AI Suite add-on for documentation workflows.$q$]::text[], 0);
