INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$How much does Outline cost?$q$, $q$Cloud-hosted plans start at $10/month for the Starter plan (1-10 members), $79/month for Team (11-100 members), and $249/month for Business (101-200 members).$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Can Outline be self-hosted?$q$, $q$Yes, Outline is open source and can be self-hosted on your own infrastructure instead of using the cloud-hosted plans.$q$, 1);
