INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$overview$q$, $q$What is Honeybadger?$q$, 2, ARRAY[$q$Honeybadger is a monitoring platform, founded in 2012, that combines error tracking, application performance monitoring, uptime monitoring, and structured logging into one product for development teams.$q$, $q$It supports Ruby, JavaScript, Python, Elixir, PHP, Go, Java, Crystal, and .NET, and integrates with tools like GitHub, Slack, PagerDuty, and JIRA.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$who-its-for$q$, $q$Who Honeybadger is for$q$, 2, ARRAY[$q$Honeybadger is aimed at development teams who want a single, developer-first tool for error tracking, uptime, and cron monitoring instead of maintaining separate bespoke tools.$q$]::text[], 1);
