INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$who-its-for$q$, $q$Who Pingdom is for$q$, 2, ARRAY[$q$Teams that need globally distributed uptime checks and transaction monitoring for critical flows like checkout or login, backed by an established enterprise vendor.$q$]::text[], 1);
