INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87089195-3dd1-46cf-905d-b16e26fbbd31', $q$overview$q$, $q$What is Checkly?$q$, 2, ARRAY[$q$Checkly is a monitoring platform for API, browser, and uptime checks that developers configure as code using its CLI, Terraform, or Pulumi provider.$q$, $q$It includes Playwright-based synthetic monitoring, heartbeat checks, smart alerting, branded status pages, and an AI-assisted root cause analysis feature.$q$]::text[], 0);
