INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a088bca4-e021-4feb-af5d-c1d5769b5a38', $q$who-its-for$q$, $q$Who AppSignal is for$q$, 2, ARRAY[$q$AppSignal suits Ruby, Elixir, Node.js and Python teams that want a single tool for errors, performance and logs instead of stitching together separate monitoring services.$q$]::text[], 1);
