INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$overview$q$, $q$What is Scout APM?$q$, 2, ARRAY[$q$Scout APM (branded Scout Monitoring) is an application performance monitoring tool that gives development teams code-level traces, integrated error monitoring, and log management with minimal configuration.$q$, $q$It supports Ruby, Python, PHP, Elixir and Node.js frameworks, and includes an MCP server for integrating production performance data with AI coding assistants.$q$]::text[], 0);
