INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e44be36-57f9-4e4f-b5f8-22e6508f69b4', $q$overview$q$, $q$What is Mouseflow?$q$, 2, ARRAY[$q$Mouseflow is a behavior analytics platform that records 100% of sessions and combines heatmaps, funnels, journey analytics and form analytics to help teams find friction and improve conversion.$q$, $q$Mina AI provides real-time guidance on recordings and heatmaps, and a free forever plan is available alongside paid tiers starting at $25/month.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e44be36-57f9-4e4f-b5f8-22e6508f69b4', $q$who-its-for$q$, $q$Who Mouseflow is for$q$, 2, ARRAY[$q$It's suited to marketing, product and e-commerce teams that want to understand and fix where users struggle or drop off on their site.$q$]::text[], 1);
