INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$Deploys apps as VMs in regions close to end users worldwide$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$Usage-based pricing with no complex tiered plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$Managed Postgres, Kubernetes and storage options built in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$Distributed, remote-first team operating since 2017$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$No published flat starting price; billing depends on machine size, storage and data transfer$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$Legacy free allowances (shared-cpu VMs and storage) have been discontinued$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$Higher-touch support beyond community tier is a separate paid add-on$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$How is Fly.io priced?$q$, $q$Usage-based, billed per organization for Machines, storage, snapshots and data transfer.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$Does Fly.io have a free tier?$q$, $q$Previous free allowances (e.g. 3 shared-cpu-1x VMs, 3GB storage) have been discontinued; pricing is now pay-as-you-go.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$When was Fly.io founded?$q$, $q$2017.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$Does Fly.io offer paid support plans?$q$, $q$Yes, a 'Serious Support' plan starting at $29/month gives access to dedicated engineers.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$Global app deployment$q$, $q$Deploy containerized apps as VMs in regions near end users to reduce latency.$q$, $q$Backend engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$Managed database hosting$q$, $q$Run managed Postgres alongside application workloads on the same platform.$q$, $q$Teams needing integrated databases$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$Pay-as-you-go$q$, $q$Usage-based ($0.0028-$0.3577/hour per Machine)$q$, NULL, $q$["Started Machines billed hourly","Stopped Machines $0.15/GB rootfs/month","Volumes $0.15/GB/month","Volume Snapshots $0.08/GB/month (first 10GB free)","Data Transfer $0.02-$0.12/GB"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$Serious Support$q$, $q$$29/month$q$, $q$monthly$q$, $q$["Access to dedicated engineers"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$HIPAA Compliance Package$q$, $q$$99/month$q$, $q$monthly$q$, $q$["BAAs and SOC2 documentation for HIPAA workloads"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$overview$q$, $q$What is Fly.io?$q$, 2, ARRAY[$q$Fly.io is a developer-focused cloud platform for deploying applications as VMs (Fly Machines) in regions close to end users, with managed Postgres, persistent storage, global load balancing and Kubernetes support.$q$, $q$Pricing is entirely usage-based rather than tiered plans, and the company has operated as a distributed, remote-first team since 2017.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', $q$who-its-for$q$, $q$Who Fly.io is for$q$, 2, ARRAY[$q$It's aimed at developers and backend teams who want to run apps and databases physically close to their users worldwide without managing traditional cloud infrastructure directly.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('11db7b95-8347-45df-a13b-c3e8b6ea53f7', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Multi-cloud deployments$q$, $q$Deploy services, jobs, and databases across AWS, GCP, Azure, Oracle Cloud, CoreWeave, or Civo, including bring-your-own-cloud setups.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$GPU workloads and inference$q$, $q$Run GPU-backed workloads and model inference, including open-source models like Llama4 and Deepseek.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$CI/CD and GitOps$q$, $q$Built-in CI/CD pipelines and GitOps workflows for automating builds and deployments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Kubernetes automation$q$, $q$Automates Kubernetes cluster management across cloud environments without requiring manual cluster ops.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Secrets management and multi-tenancy$q$, $q$Centralized secrets handling and multi-tenant project isolation for teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Preview environments and sandboxes$q$, $q$Spin up preview environments and sandboxes for testing changes before production.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Supports multiple cloud providers and bring-your-own-cloud deployments$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Pay-as-you-go pricing with a free Sandbox tier to start$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Built-in support for GPU and AI inference workloads$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$SOC 2 Type 2 and HIPAA certified$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Compute pricing is broken into many named plan tiers, which can be confusing to compare$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Enterprise-level SLAs and support require custom/quote-based pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$No fixed-price low-end plan beyond the limited free Sandbox tier$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Does Northflank have a free plan?$q$, $q$Yes, the Sandbox tier is free and includes 2 services, 1 database, and 2 cron jobs.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$What clouds does Northflank support?$q$, $q$Northflank supports AWS, GCP, Azure, Oracle Cloud, CoreWeave, and Civo, plus bring-your-own-cloud deployments.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Can I run GPU workloads on Northflank?$q$, $q$Yes, Northflank offers GPU options including NVIDIA L4, A100, and H100 instances billed hourly.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$When was Northflank founded?$q$, $q$Northflank was founded in 2019 and is headquartered in London, United Kingdom.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Internal developer platforms$q$, $q$Teams use Northflank to build a self-service deployment layer across multiple clouds.$q$, $q$Platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$AI/ML inference hosting$q$, $q$Deploy and serve open-source AI models with GPU-backed compute.$q$, $q$AI and ML teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Sandbox$q$, $q$Free$q$, NULL, $q$["2 services","1 database","2 cron jobs"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Pay-as-you-go$q$, $q$From $2.70/month (nf-compute-10)$q$, $q$monthly$q$, $q$["Consumption-based compute","No seat pricing","Scales to 20 dedicated vCPUs"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["SLAs","24/7 support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$overview$q$, $q$What is Northflank?$q$, 2, ARRAY[$q$Northflank is a deployment platform that lets teams run containers, databases, jobs, and AI/GPU workloads across AWS, GCP, Azure, Oracle Cloud, and other providers, or bring their own cloud account.$q$, $q$It combines CI/CD pipelines, GitOps, and Kubernetes automation so teams can deploy without managing cluster operations directly.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$who-its-for$q$, $q$Who Northflank is for$q$, 2, ARRAY[$q$Northflank is aimed at platform engineering teams building internal developer platforms and at AI/ML teams that need GPU-backed inference or training infrastructure across multiple clouds.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
