INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$Unified infrastructure API$q$, $q$A single API layer over CI/CD, Kubernetes, Terraform, secrets management, and monitoring.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$Environment as a primitive$q$, $q$Environments are treated as first-class objects that can be created, cloned, and torn down programmatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$RBAC and governance for AI agents$q$, $q$Role-based access control and governance policies apply to both human users and AI agents operating infrastructure.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$Audit trails and rollback$q$, $q$Full action attribution with audit logs and built-in rollback of infrastructure changes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$200+ integrations$q$, $q$Integrates with cloud providers (AWS EKS, GCP GKE, Azure AKS, Scaleway), CI tools, Terraform, Vault, Datadog, and Prometheus.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$MCP Server and AI Skills$q$, $q$Native Model Context Protocol server so AI coding agents like Claude, Cursor, Codex, and Gemini CLI can operate infrastructure.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$Works across AWS, GCP, Azure, Scaleway, and on-premise Kubernetes$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$Built-in audit trails and rollback for infrastructure changes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$Native integration for AI coding agents via an MCP server$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$SOC 2 Type II, HIPAA, and GDPR compliant, aimed at regulated industries$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$No public free tier; entry Team plan starts at $899/month$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$Enterprise pricing is custom/quote-only$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$Founding year and headquarters are not disclosed on the site$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$How much does Qovery cost?$q$, $q$The Team plan starts at $899/month, Business starts at $1,999/month, and Enterprise is custom-priced.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$Does Qovery support AI agents?$q$, $q$Yes, Qovery includes an MCP Server and AI Skills so AI coding agents can provision and manage infrastructure under the same RBAC controls as humans.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$What clouds does Qovery support?$q$, $q$Qovery supports AWS EKS, GCP GKE, Azure AKS, Scaleway, and on-premise Kubernetes.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$Is Qovery suitable for regulated industries?$q$, $q$Yes, Qovery is SOC 2 Type II, HIPAA, GDPR, and DORA compliant and is marketed to financial services, healthcare, and insurtech companies.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$Regulated infrastructure operations$q$, $q$Teams in finance, healthcare, and insurance use Qovery's governance and audit trails to control infrastructure changes.$q$, $q$Platform engineers in regulated industries$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$AI-agent-driven infrastructure$q$, $q$Organizations let AI coding agents provision and scale environments through Qovery's unified API under RBAC policy.$q$, $q$Engineering leaders adopting AI agents$q$, 1);
