INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46c7eebc-d6a3-4c06-b0fb-74483d16333d', $q$overview$q$, $q$What is Qovery?$q$, 2, ARRAY[$q$Qovery is an infrastructure orchestration platform that puts CI/CD, Kubernetes, Terraform, secrets management, and monitoring behind a single API.$q$, $q$It is designed so both human engineers and AI coding agents can provision, scale, and roll back infrastructure changes under the same role-based access controls and audit trails.$q$]::text[], 0);
