INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f36c751-0719-4122-8fe0-e1bd976404d2', $q$who-its-for$q$, $q$Who Cloudways is for$q$, 2, ARRAY[$q$Cloudways is built for agencies, developers, and eCommerce businesses that want managed cloud infrastructure with a choice of underlying cloud provider, rather than being locked into one vendor's stack.$q$]::text[], 1);
