INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8dd02588-9e72-460d-8c15-9f28eeaf959d', $q$overview$q$, $q$What is Pantheon?$q$, 2, ARRAY[$q$Pantheon is a WebOps platform for building, hosting, and operating WordPress, Drupal, and Next.js websites, with a standardized Dev/Test/Live environment workflow built into every site.$q$, $q$Development is free on 2 sandbox sites per account; going live requires a paid site plan, with pricing based on monthly visits and traffic.$q$]::text[], 0);
