INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('651a0f94-72a0-43b1-b2b0-60746e97bceb', $q$Are firewalls included?$q$, $q$Yes, Hetzner includes free stateful firewalls with its cloud servers.$q$, 2);
