INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Deploying apps without managing servers$q$, $q$Push code via Git and let Clever Cloud handle builds, scaling, and updates.$q$, $q$Developers and small engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Compliance-sensitive hosting$q$, $q$Run workloads under ISO 27001, HDS, and GDPR-compliant French infrastructure.$q$, $q$European regulated industries (e.g. healthcare)$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$overview$q$, $q$What is Clever Cloud?$q$, 2, ARRAY[$q$Clever Cloud, founded in 2010 in Nantes, France, is a sovereign, fully managed Platform-as-a-Service for deploying and operating applications and managed databases.$q$, $q$It bills per second based on actual usage, supports 15+ language runtimes, and holds ISO 27001, HDS, and GDPR compliance certifications for regulated workloads.$q$]::text[], 0);
