INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$Git/Docker deployment$q$, $q$Deploy applications directly from Git or Docker with automatic builds and CI/CD.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$Preview environments$q$, $q$Isolated preview environments generated for every pull request.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$Zero-downtime deploys$q$, $q$Zero-downtime deployments with automatic Kubernetes cluster upgrades.$q$, 2);
