INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$Porter's fees are separate from and additional to the underlying cloud provider's own infrastructure costs$q$, 0);
