INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$No general free tier; only a startup program offering 6 months free for eligible companies$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$Where does Porter run applications?$q$, $q$Inside the customer's own AWS, GCP, or Azure cloud account, not a shared Porter-hosted environment.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$How is Porter priced?$q$, $q$Usage-based: $6/month per GB of RAM and $13/month per vCPU, on the Standard plan, plus underlying cloud provider costs.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$Is there a free trial?$q$, $q$Porter's startup program offers 6 months free rather than a standard free trial.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$Does Porter support HIPAA compliance?$q$, $q$Yes, it offers a one-click HIPAA compliance option alongside SOC 2 Type II certification.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$Deploying to your own cloud account$q$, $q$Run production apps on your own AWS/GCP/Azure account without managing Kubernetes directly.$q$, $q$Engineering teams wanting cloud ownership$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$PR-based preview environments$q$, $q$Automatically spin up isolated environments for every pull request.$q$, $q$Product and engineering teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$Standard$q$, $q$$6/GB RAM + $13/vCPU per month$q$, $q$monthly$q$, $q$["Deploy from GitHub","Unlimited applications","Preview environments","Autoscaling","Jobs & cron jobs","Monitoring","Logging","Alerting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$Enterprise$q$, $q$Custom (from 40 vCPU / 80GB RAM)$q$, NULL, $q$["Everything in Standard","Premium support","Advanced RBAC","SAML-based SSO","Custom alerts","On-prem installation"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', $q$overview$q$, $q$What is Porter?$q$, 2, ARRAY[$q$Porter is a Platform-as-a-Service that runs applications inside a customer's own AWS, GCP, or Azure account, handling networking, CI/CD, and autoscaling on top of Kubernetes.$q$, $q$It bills on a usage basis ($6/month per GB RAM, $13/month per vCPU) separate from the underlying cloud provider's costs, and is SOC 2 Type II certified with an Enterprise tier for larger deployments.$q$]::text[], 0);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8224f1c4-4b8e-465f-bf52-2dfa9e59e1ef', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
