INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Does Zeabur have a free plan?$q$, $q$Yes, Zeabur offers a Free plan with one manageable server, community support, and 48-hour log retention.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Do paid plans include a free trial?$q$, $q$Yes, the Dev and Pro plans include the first 14 days free.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$What is the Zeabur AI Agent?$q$, $q$It turns natural-language instructions into infrastructure actions such as renting servers, deploying services, or accessing AI models; full access requires the Pro plan.$q$, 2);
