INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Team infrastructure collaboration$q$, $q$The Team plan adds role and permission management for groups managing shared infrastructure.$q$, $q$Small engineering teams$q$, 2);
