INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$overview$q$, $q$What is Zeabur?$q$, 2, ARRAY[$q$Zeabur is a DevOps platform that automates deployment by detecting a codebase's language and framework and provisioning the required infrastructure automatically.$q$, $q$Beyond hosting, it offers an AI Hub for accessing multiple AI models through a single API, plus domain, DNS, and email services.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$who-its-for$q$, $q$Who Zeabur is for$q$, 2, ARRAY[$q$Zeabur suits developers who want to deploy applications quickly without manually configuring servers, and teams building AI-powered products who need model access alongside hosting.$q$]::text[], 1);
