INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Enterprise pricing is custom/quote-based, starting around $1,000/month$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Does Koyeb have a free plan?$q$, $q$Koyeb offers a free 5-hour serverless Postgres tier, but app hosting plans start at $29/month for the Pro tier.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$What GPUs does Koyeb support?$q$, $q$Koyeb offers GPU options including RTX-4000-SFF-ADA, L4, RTX-A6000, L40S, A100, and H100 on a pay-as-you-go basis.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Can I deploy without changing my code?$q$, $q$Yes, Koyeb supports Docker containers and popular programming languages without requiring code modifications.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Does Koyeb offer startup credits?$q$, $q$Yes, qualifying early-stage startups can receive up to $30,000 in credits.$q$, 3);
