INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$overview$q$, $q$What is Koyeb?$q$, 2, ARRAY[$q$Koyeb is a serverless cloud infrastructure platform built for deploying AI applications, APIs, and databases at scale.$q$, $q$It provides pay-as-you-go access to GPUs, CPUs, and accelerators, along with a managed serverless Postgres database with pgvector support.$q$]::text[], 0);
