INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Is Stormkit free to use?$q$, $q$Yes, Stormkit offers a Free plan with unlimited usage and community support, with no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$What frameworks does Stormkit support?$q$, $q$Stormkit supports Node.js, Astro, Nuxt, Next.js, Svelte, TanStack, FastAPI, Go, and more.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Can I self-host Stormkit?$q$, $q$Yes, Stormkit offers a self-hosted version that keeps deployments on your own infrastructure.$q$, 2);
