INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Vendor-independent app hosting$q$, $q$Teams that want Vercel/Netlify-style Git deployments without vendor lock-in can self-host Stormkit.$q$, $q$Privacy-conscious engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Multi-framework deployment$q$, $q$Developers can deploy apps built with Next.js, Nuxt, Astro, Svelte, FastAPI, and Go from the same platform.$q$, $q$Full-stack developers$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, $q$["Unlimited usage","Community support"]$q$::jsonb, 0);
