INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$Ultimate$q$, $q$$100/month$q$, $q$monthly$q$, $q$["Premium support via Slack, Discord, or Teams"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$overview$q$, $q$What is Stormkit?$q$, 2, ARRAY[$q$Stormkit is a deployment and hosting platform that automates Git-based CI/CD, positioning itself as a self-hosted alternative to Vercel and Netlify.$q$, $q$It supports zero-downtime rolling deployments, custom domains with automatic TLS, and frameworks including Next.js, Nuxt, Astro, Svelte, and FastAPI.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b67fa90-7a4e-4cd5-aaaf-5828ca0f9a2a', $q$who-its-for$q$, $q$Who Stormkit is for$q$, 2, ARRAY[$q$Stormkit is built for teams that want Git-triggered deployments without depending on a third-party hosting vendor, from solo developers to enterprises needing audit logs and custom TLS.$q$]::text[], 1);
