INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Instant branching$q$, $q$Clone any Postgres database in seconds regardless of size using copy-on-write storage.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Copy-on-write storage$q$, $q$Branches share parent data and only store the differences, reducing storage costs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Scale-to-zero$q$, $q$Idle branches hibernate and consume no compute.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Instant wake-up$q$, $q$Branches respond immediately without spin-up delay.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Vanilla PostgreSQL$q$, $q$Runs unmodified upstream PostgreSQL rather than a forked engine.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Production features$q$, $q$Includes read replicas, point-in-time recovery, and built-in observability.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Copy-on-write branching avoids duplicating full database storage for every branch$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Free, self-managed Open Source tier available forever$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Runs vanilla PostgreSQL rather than a proprietary fork$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Built specifically for isolating database branches for AI coding agents and PR previews$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Fully managed Xata Cloud pricing is pay-as-you-go (hourly compute + storage), which can be harder to predict than flat plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$BYOC (bring-your-own-cloud) requires a custom sales quote$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Is Xata free to use?$q$, $q$Yes, the Open Source tier is free forever for self-managed deployments.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$How does Xata pricing work?$q$, $q$Xata Cloud is billed pay-as-you-go at $0.012/hour of compute plus $0.28/GB per month of storage, with instance tiers from Micro ($9/month) to 8xlarge ($1,121/month).$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$What is copy-on-write branching?$q$, $q$It's a technique where database branches share the parent's data and only store changes, so cloning a database doesn't duplicate its full storage.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Does Xata support standard PostgreSQL?$q$, $q$Yes, Xata runs 100% upstream PostgreSQL without significant modifications.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Database branching for pull requests$q$, $q$Teams can spin up an isolated database clone for every PR or preview deployment without duplicating storage.$q$, $q$Engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Safe testing for AI coding agents$q$, $q$Coding agents can be given isolated database branches to test and execute changes safely.$q$, $q$Teams building with AI coding agents$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Open Source$q$, $q$Free forever$q$, NULL, $q$["Branching","Scale-to-zero","Standard anonymization","Self-managed provisioning","Community support","~10s wake-up time"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Xata Cloud$q$, $q$$0.012/hr + $0.28/GB/mo storage (instance tiers from $9/mo to $1,121/mo)$q$, NULL, $q$["Branching","Scale-to-zero","~1s wake-up time","Standard anonymization","Fully managed provisioning","Standard support","Observability","SOC 2 and GDPR compliance","Multi-region (AWS, GCP)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$BYOC$q$, $q$Custom quote$q$, NULL, $q$["Advanced anonymization (HIPAA)","Your cloud provisioning","24/7 dedicated support","SOC 2, GDPR, and BAA compliance","Multi-region (AWS, Azure, GCP)"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$overview$q$, $q$What is Xata?$q$, 2, ARRAY[$q$Xata is a Postgres database platform built around instant, copy-on-write branching, allowing teams to clone production-scale databases in seconds without duplicating storage.$q$, $q$It runs unmodified upstream PostgreSQL and adds scale-to-zero hibernation, instant wake-up, read replicas, and point-in-time recovery.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$who-its-for$q$, $q$Who Xata is for$q$, 2, ARRAY[$q$Xata targets engineering teams that need isolated database environments for pull requests, preview deployments, and AI coding agents that must safely test changes against real data.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
