INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Business/Enterprise tier has a $2,500/month minimum$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Self-hosted VPC deployment is listed as coming soon, not yet generally available$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Does Convex have a free plan?$q$, $q$Yes, the Free & Starter tier is available at $0/month with pay-as-you-go overage charges.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$How is the Professional plan priced?$q$, $q$The Professional plan costs $25 per developer per month, supporting 1-20 developer seats.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$What language does Convex use?$q$, $q$Convex is built around TypeScript, with end-to-end type safety from the database to the client.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Is Convex compliant with security standards?$q$, $q$Yes, Convex is SOC 2 Type II certified and HIPAA compliant.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Real-time app backends$q$, $q$Convex's reactive database automatically syncs data changes to connected clients without manual websocket setup.$q$, $q$Full-stack TypeScript developers$q$, 0);
