INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Enterprise backend infrastructure$q$, $q$Larger organizations can use SSO, RBAC, and dedicated deployments under the Business/Enterprise plan.$q$, $q$Enterprises$q$, 2);
