INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$overview$q$, $q$What is Convex?$q$, 2, ARRAY[$q$Convex is a reactive backend platform that combines a database, serverless functions, workflows, real-time sync, search, and file storage behind a TypeScript-first API.$q$, $q$It emphasizes end-to-end type safety and ACID transactions, and includes integrations for AI coding agents such as Claude Code and Codex.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$who-its-for$q$, $q$Who Convex is for$q$, 2, ARRAY[$q$Convex is aimed at TypeScript developers who want a single reactive backend instead of stitching together a database, functions, and real-time infrastructure separately, including teams that rely on AI coding agents.$q$]::text[], 1);
