INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('29a999ee-1d55-4fa7-a5bf-265fba6c2681', $q$Enterprise-grade compliance (SOC-2, HIPAA, SSO) requires a custom Enterprise plan$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('29a999ee-1d55-4fa7-a5bf-265fba6c2681', $q$Is Appwrite open source?$q$, $q$Yes, Appwrite is an open-source backend platform with a public GitHub repository.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('29a999ee-1d55-4fa7-a5bf-265fba6c2681', $q$Does Appwrite have a free plan?$q$, $q$Yes, the Free plan includes 5GB bandwidth, 2GB storage, and 750K executions, limited to 2 projects.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('29a999ee-1d55-4fa7-a5bf-265fba6c2681', $q$What does the Pro plan cost?$q$, $q$The Pro plan starts from $25/month and includes 2TB bandwidth, 150GB storage, and unlimited databases and functions.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('29a999ee-1d55-4fa7-a5bf-265fba6c2681', $q$What languages and frameworks does Appwrite support?$q$, $q$Appwrite supports 30+ frameworks and languages including React, Next.js, Vue, Flutter, Node.js, Python, PHP, Swift, and Kotlin.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('29a999ee-1d55-4fa7-a5bf-265fba6c2681', $q$Unified backend for web and mobile apps$q$, $q$Teams can use one platform for auth, database, storage, and functions instead of stitching together separate services.$q$, $q$Full-stack and mobile developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('29a999ee-1d55-4fa7-a5bf-265fba6c2681', $q$Serverless site hosting$q$, $q$Appwrite Sites offers an open-source alternative to Vercel for deploying web projects.$q$, $q$Frontend developers$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('29a999ee-1d55-4fa7-a5bf-265fba6c2681', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, $q$["5GB bandwidth","2GB storage","750K executions","75K monthly active users","Community support","1 database, 1 bucket, 2 functions per project","Max 2 projects"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('29a999ee-1d55-4fa7-a5bf-265fba6c2681', $q$Pro$q$, $q$From $25/month$q$, $q$monthly$q$, $q$["2TB bandwidth","150GB storage","3.5M executions","200K monthly active users","Email support","Daily backups (7-day retention)","Unlimited databases, buckets, and functions","45-minute build timeouts"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('29a999ee-1d55-4fa7-a5bf-265fba6c2681', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Everything in Pro","Uptime SLAs","Dedicated success manager","Up to 24/7 support","SOC-2, HIPAA, and BAA compliance","SSO","90-day log retention"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('29a999ee-1d55-4fa7-a5bf-265fba6c2681', $q$overview$q$, $q$What is Appwrite?$q$, 2, ARRAY[$q$Appwrite is an open-source backend platform that bundles authentication, databases, storage, serverless functions, messaging, and realtime subscriptions into one product.$q$, $q$It supports over 30 frameworks and languages, including React, Next.js, Flutter, and Swift, and also offers Sites, an open-source alternative to Vercel.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('29a999ee-1d55-4fa7-a5bf-265fba6c2681', $q$who-its-for$q$, $q$Who Appwrite is for$q$, 2, ARRAY[$q$Appwrite is built for development teams building web and mobile apps who want a single open-source backend instead of assembling separate auth, database, and storage services.$q$]::text[], 1);
