INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Realtime database$q$, $q$Embedded database with a schema builder, validations, REST API, and real-time subscriptions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Authentication$q$, $q$Email/password and OAuth2 sign-in support for Google, Facebook, GitHub, and GitLab.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$File storage$q$, $q$Local or S3-compatible storage with on-the-fly thumbnail generation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Admin dashboard$q$, $q$Built-in UI for managing collections, records, and users.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Extensibility$q$, $q$Can be extended with Go and JavaScript hooks or run standalone.$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Ships as a single executable with no external dependencies to install$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Fully open source and self-hosted, with no vendor lock-in$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Official JavaScript/TypeScript and Dart SDKs are provided$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Includes OAuth2 sign-in for Google, Facebook, GitHub, and GitLab out of the box$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Self-hosted only — no official managed cloud hosting is offered on the site$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Built and maintained primarily by a single creator, which may affect long-term support capacity$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Is PocketBase free?$q$, $q$Yes, PocketBase is open source and free to self-host.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$What language is PocketBase written in?$q$, $q$PocketBase is built with Go and distributed as a single executable.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Does PocketBase support OAuth login?$q$, $q$Yes, it supports OAuth2 sign-in with Google, Facebook, GitHub, and GitLab, in addition to email/password.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Can I extend PocketBase's backend logic?$q$, $q$Yes, PocketBase can be extended using Go or JavaScript hooks.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Self-hosted app backend$q$, $q$Developers can run a full backend (database, auth, storage) from one binary without managing separate services.$q$, $q$Solo developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Mobile and frontend app backends$q$, $q$Official JS/TS and Dart SDKs let PocketBase serve as the backend for Flutter, React, Vue, and Angular apps.$q$, $q$Mobile and frontend developers$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$overview$q$, $q$What is PocketBase?$q$, 2, ARRAY[$q$PocketBase is an open-source backend that ships as a single Go executable, bundling a realtime database, authentication, file storage, and an admin dashboard.$q$, $q$It can be run standalone or extended with Go and JavaScript hooks, with official SDKs for JavaScript/TypeScript and Dart.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$who-its-for$q$, $q$Who PocketBase is for$q$, 2, ARRAY[$q$PocketBase suits developers who want a self-hosted backend with zero vendor lock-in for apps built with Flutter, Svelte, Vue, React, or Angular.$q$]::text[], 1);
