INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Starter (free) projects are limited to 1 project and pause after a week of inactivity$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$SOC 2 Type II compliance and SLA support require the $599/month Team plan$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Does Nhost have a free plan?$q$, $q$Yes, the Starter plan is $0/month with 1 GB database, 1 GB storage, and unlimited users, limited to 1 project.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$How much does the Pro plan cost?$q$, $q$The Pro plan starts from $25/month and includes $15 of compute credits, 10 GB database, and 50 GB storage.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$What database does Nhost use?$q$, $q$Nhost uses PostgreSQL with an instant GraphQL API layer on top.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Does Nhost support external database connections?$q$, $q$Yes, external database connections are available starting on the Team plan.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Full-stack app backend$q$, $q$Developers get a Postgres database, GraphQL API, auth, storage, and functions in one managed service.$q$, $q$Full-stack developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Startup MVPs to scaling products$q$, $q$Nhost is positioned for use from indie side projects up to the core infrastructure of scaling startups.$q$, $q$Indie hackers and startups$q$, 1);
