INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Pro$q$, $q$From $25/month$q$, $q$monthly$q$, $q$["$15 compute credits included","10 GB database","50 GB storage","50 GB egress","Automated backups","Point-in-time recovery","Managed Grafana","Email support","Unlimited projects"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Team$q$, $q$From $599/month$q$, $q$monthly$q$, $q$["SOC 2 Type II","Email support SLA","Dedicated Discord channel","External database connections","Advanced GraphQL features","Unlimited team members"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Everything in Team","SLAs","Dedicated account manager","Dedicated clusters (add-on)"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$overview$q$, $q$What is Nhost?$q$, 2, ARRAY[$q$Nhost is a managed backend platform built around PostgreSQL, providing an instant GraphQL API alongside authentication, file storage, and serverless functions.$q$, $q$It also offers container support for other languages and an AI toolkit with embeddings and assistants, deployed across 6 regions and 80+ CDN locations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea768a9c-a511-4333-8959-87593d0426a5', $q$who-its-for$q$, $q$Who Nhost is for$q$, 2, ARRAY[$q$Nhost targets developers who want a fully managed Postgres + GraphQL backend, ranging from indie hackers building side projects to startups scaling their core infrastructure.$q$]::text[], 1);
