INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$PostgreSQL compatibility$q$, $q$Supports stored procedures, triggers, and extensions from the PostgreSQL ecosystem.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Automatic sharding and scaling$q$, $q$Distributes and scales data horizontally without application downtime.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Multi-region high availability$q$, $q$Built-in resilience with multi-region disaster recovery.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Vector indexing$q$, $q$Advanced vector indexing for RAG and GenAI applications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Enterprise security$q$, $q$End-to-end encryption, connection management, and observability tooling.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Multi-model support$q$, $q$Handles relational, document, and graph-style workloads.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Full PostgreSQL compatibility eases migration for existing Postgres applications$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Free, downloadable open-source version$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Free-tier managed YugabyteDB Aeon account available for getting started$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Multi-region high availability and disaster recovery built in$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Aeon add-ons like Enterprise Security and Business Continuity/DR cost extra ($25/vCPU/month each)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Enterprise tier pricing is custom/quote-only$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Additional charges apply for disk storage, backup storage, data transfer, and provisioned IOPS beyond compute pricing$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Is YugabyteDB open source?$q$, $q$Yes, the open-source version is free to download and self-host.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Is there a managed cloud version?$q$, $q$Yes, YugabyteDB Aeon is the managed cloud service, with a free tier account available to start.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$How much does YugabyteDB Aeon cost?$q$, $q$The Standard plan starts at $125/vCPU/month and Professional at $167/vCPU/month; Enterprise pricing is custom.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$What clouds does it run on?$q$, $q$AWS, Google Cloud, and Microsoft Azure, plus Kubernetes and hybrid/edge environments.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Globally distributed transactional apps$q$, $q$Runs PostgreSQL-compatible workloads across regions with automatic sharding and HA.$q$, $q$Platform and backend engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$AI/RAG applications$q$, $q$Uses built-in vector indexing to support retrieval-augmented generation over relational data.$q$, $q$AI/ML engineering teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Standard$q$, $q$$125/vCPU/month$q$, $q$monthly$q$, $q$["Core database features","PostgreSQL and Cassandra APIs","Basic security/networking","24/7 support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Professional$q$, $q$$167/vCPU/month$q$, $q$monthly$q$, $q$["All Standard features","Global deployment topologies","Enhanced observability with Performance Advisor","Optional Enterprise Security / Business Continuity add-ons at $25/vCPU/month each"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["All Professional features","Enterprise security","Business continuity/DR built in","Enterprise integrations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$overview$q$, $q$What is YugabyteDB?$q$, 2, ARRAY[$q$YugabyteDB is a distributed SQL database that is compatible with PostgreSQL, built by former Facebook engineers starting in February 2016.$q$, $q$It's available as free open-source software or as YugabyteDB Aeon, a managed database-as-a-service with a free tier to get started.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', $q$who-its-for$q$, $q$Who YugabyteDB is for$q$, 2, ARRAY[$q$Teams building cloud-native, globally distributed applications who want PostgreSQL compatibility along with horizontal scaling and multi-region resilience.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('78eada95-da81-4cfa-9a33-f04a9d8c15e0', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
