INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Native vector search$q$, $q$Built-in vector indexing and retrieval for RAG applications.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Unified HTAP engine$q$, $q$Combines transactional, analytical, and vector query capabilities in one system.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Elastic autoscaling$q$, $q$Scales compute up or down to zero based on demand.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Distributed ACID transactions$q$, $q$Maintains consistent state across distributed nodes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Workload isolation$q$, $q$Dedicated throughput (Request Unit) quotas prevent resource contention.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$MySQL-compatible SQL$q$, $q$Uses standard SQL syntax with integrations for LangChain, LlamaIndex, and MCP.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Starter plan includes a genuine free monthly allowance (25GiB row storage, 25GiB column storage, 250M Request Units)$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Scale-to-zero reduces costs for intermittent workloads$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Combines transactional, analytical, and vector search in a single database$q$, 2);
