INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Premium tier starts at $1,800/month$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Dedicated tier requires a $1,376/month minimum commitment$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Is TiDB Cloud free to start?$q$, $q$Yes, the Starter plan includes a free monthly allowance of storage and Request Units before pay-as-you-go charges apply.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Does TiDB Cloud support vector search?$q$, $q$Yes, it has native vector search and RAG capabilities integrated into the same engine as its SQL workloads.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$What cloud providers are supported?$q$, $q$TiDB Cloud Dedicated is available on AWS, Google Cloud, and Azure.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Is TiDB open source?$q$, $q$TiDB is an open-source distributed SQL database; TiDB Cloud is PingCAP's managed offering of it, alongside a self-managed option.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$HTAP workloads$q$, $q$Runs transactional and analytical queries against the same data without separate ETL pipelines.$q$, $q$Data platform teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$RAG and AI applications$q$, $q$Combines native vector search with relational data for retrieval-augmented generation.$q$, $q$AI application developers$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Starter$q$, $q$$0/month + pay-as-you-go$q$, $q$monthly$q$, $q$["25GiB row storage + 25GiB column storage free","250M Request Units free per month","$0.20/GiB additional storage","$0.10 per 1M additional RUs","Scale-to-zero"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Essential (Preview)$q$, $q$~$20/day (typical small production)$q$, NULL, $q$["Autoscaling up to 100K Request Units","Point-in-time backup with up to 30-day retention","Encryption in transit and at rest"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Premium (Preview)$q$, $q$From $1,800/month$q$, $q$monthly$q$, $q$["Unlimited autoscaling compute","Enterprise security (CMEK, PrivateLink, VPC Peering)","99.99% availability with multi-zone protection"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Dedicated$q$, $q$From $0.22/hour ($1,376/month minimum)$q$, NULL, $q$["4-32 vCPU node options","PCI-DSS and SOC 2 Type II compliant","Available on AWS, Google Cloud, and Azure"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$overview$q$, $q$What is TiDB Cloud?$q$, 2, ARRAY[$q$TiDB Cloud is PingCAP's managed version of TiDB, an open-source distributed SQL database founded in 2015 that unifies transactional, analytical, and vector search workloads.$q$, $q$It offers a free Starter tier with a real monthly allowance, plus usage-based Essential, Premium, and Dedicated tiers for production workloads.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$who-its-for$q$, $q$Who TiDB Cloud is for$q$, 2, ARRAY[$q$Teams that need a single database for mixed transactional and analytical (HTAP) workloads, or that want native vector search alongside relational data for AI/RAG apps.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
