INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Native GraphQL API$q$, $q$Supports schema-driven application development directly via GraphQL, alongside property-graph queries.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Horizontal distribution$q$, $q$Data is sharded and distributed with automatic rebalancing across the cluster.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$ACID transactions$q$, $q$Provides ACID transactions with linearizable reads for consistent replication.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Full-text search and regex$q$, $q$Built-in full-text search and regular expression matching on stored data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Geo search$q$, $q$Native geographic search capability.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Multiple protocols$q$, $q$Responds via gRPC, HTTP, JSON, and Protocol Buffers.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Fully open source under the Apache 2.0 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Actively maintained with regular releases (v25.x as of 2026)$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Native GraphQL support removes the need for a separate API layer over the graph data$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Designed for horizontal scaling to terabyte-scale, real-time workloads$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$The original dgraph.io marketing site now redirects to documentation, with no visible pricing or company page$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Project ownership has changed hands multiple times (Dgraph Labs to Hypermode to Istari Digital), and a managed Dgraph Cloud offering could not be verified as currently active$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$No published company founding year, headquarters, or commercial pricing$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Is Dgraph still maintained?$q$, $q$Yes, the open-source project shows active development with regular releases (v25.x as of 2026).$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Is Dgraph free to use?$q$, $q$Yes, Dgraph is released under the Apache 2.0 open-source license and can be self-hosted.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Does Dgraph support GraphQL?$q$, $q$Yes, it offers a native GraphQL API in addition to direct property-graph database access.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Who owns Dgraph now?$q$, $q$Dgraph originated at Dgraph Labs, which was acquired by Hypermode, later acquired by Istari Digital; the open-source project continues to be maintained under this lineage.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Knowledge graphs and connected data$q$, $q$Stores and queries highly connected data at terabyte scale with low latency.$q$, $q$Backend engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$GraphQL-first applications$q$, $q$Uses Dgraph's native GraphQL API as the primary interface for application data.$q$, $q$Application developers$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$overview$q$, $q$What is Dgraph?$q$, 2, ARRAY[$q$Dgraph is an open-source, horizontally distributed graph database with a native GraphQL API, designed for real-time queries over terabyte-scale, highly connected data.$q$, $q$The project has changed corporate ownership several times (Dgraph Labs, then Hypermode, then Istari Digital) but remains actively maintained as open-source software.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$who-its-for$q$, $q$Who Dgraph is for$q$, 2, ARRAY[$q$Engineering teams building graph-native or GraphQL-first applications who need horizontal scalability and are comfortable self-hosting an open-source database.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Multi-model support$q$, $q$Combines vector, graph, document, time-series, and relational capabilities in a single engine.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$SurrealQL$q$, $q$A unified query language supporting graph traversal, vector search, and transactions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Built-in authentication$q$, $q$Row-level security and access control managed within the database.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Live queries$q$, $q$Real-time subscriptions for reactive applications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Spectron agent memory$q$, $q$A built-in agent memory system with entity extraction and knowledge graphs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$SurrealDS distributed storage$q$, $q$Distributed storage engine with quorum consensus and compute-storage separation.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Single engine covers document, graph, vector, and relational models, reducing the need for multiple specialized databases$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Always-free Start plan includes one instance and 1GB of storage forever$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Built-in authentication and row-level access control reduce reliance on external auth systems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Strong AI/agent-memory feature set including hybrid RAG and knowledge graph construction$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Some advertised features (database branching/forking, object-storage-backed backups) are marked 'coming soon'$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Enterprise plan pricing is custom/quote-only$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Specific self-hosted OS/platform support is not detailed on the marketing pages$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Does SurrealDB have a free tier?$q$, $q$Yes, the Start plan includes one free instance and 1GB of free storage forever, plus a no-signup-required sandbox.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$What data models does SurrealDB support?$q$, $q$It unifies document, graph, vector, time-series, and relational data models in one engine with ACID transactions.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Does SurrealDB support AI/RAG use cases?$q$, $q$Yes, it includes vector similarity search, hybrid RAG, graph-based re-ranking, and an agent memory system called Spectron.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Is there an Enterprise plan?$q$, $q$Yes, it offers self-hosted deployment, audit logging, SSO, and SLA-backed uptime, with custom pricing.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$AI agent memory and RAG$q$, $q$Uses hybrid search and knowledge graph construction to power agent memory and retrieval-augmented generation.$q$, $q$AI application developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Multi-model application backends$q$, $q$Combines graph, document, and vector data in a single database instead of stitching together multiple systems.$q$, $q$Full-stack engineering teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Start$q$, $q$$0/hr (1 free instance), then from $0.021/hr$q$, NULL, $q$["1GB storage free forever","Vertical scaling to terabytes","Automatic burst scaling","Daily automated backups","Cloud RBAC and ABAC"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Scale$q$, $q$$0.192/node/hr$q$, NULL, $q$["Highly available, fault-tolerant","Multiple availability-zone deployment","Horizontal scaling to petabytes","Multi-region disaster recovery"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Self-hosted deployments","Audit logging and compliance","SSO and advanced access controls","SLA-backed uptime guarantees","FIPS-compliant cryptography"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$overview$q$, $q$What is SurrealDB?$q$, 2, ARRAY[$q$SurrealDB is a multi-model database, registered as SurrealDB Ltd. in England and Wales, that combines documents, graphs, vectors, time-series, and relational data in one ACID-transactional engine.$q$, $q$It offers SurrealQL as a unified query language and includes built-in authentication, live queries, and an agent-memory feature set aimed at AI applications.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c12f04e-e703-497a-b9ff-e4bd73be6bd0', $q$who-its-for$q$, $q$Who SurrealDB is for$q$, 2, ARRAY[$q$Teams that want to avoid running separate document, graph, and vector databases, and AI teams building agent memory or hybrid RAG systems.$q$]::text[], 1);
