INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d00f455-f1c1-4f08-8b80-9aa4fcbc5ec0', $q$Is Meilisearch open source?$q$, $q$Yes, Meilisearch is open source and available on GitHub, with over 58,000 stars.$q$, 0);
