INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d00f455-f1c1-4f08-8b80-9aa4fcbc5ec0', $q$What languages have SDK support?$q$, $q$15+ languages including JavaScript, Python, Java, Go, Rust, and Swift, plus framework integrations for React, Vue, and Angular.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d00f455-f1c1-4f08-8b80-9aa4fcbc5ec0', $q$Does Meilisearch support AI/vector search?$q$, $q$Yes, it supports semantic and hybrid search, automated embeddings, and vector storage for RAG applications.$q$, 3);
