INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7d00f455-f1c1-4f08-8b80-9aa4fcbc5ec0', $q$Cloud (Pay-As-You-Go)$q$, $q$From $20/month$q$, $q$monthly$q$, $q$["14-day free trial, no credit card required","Fully managed infrastructure","Automatic scaling","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7d00f455-f1c1-4f08-8b80-9aa4fcbc5ec0', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Dedicated infrastructure","Up to 99.999% uptime SLA","Dedicated Slack support channel","SSO SAML and SOC 2 compliance","Advanced analytics, merchandising, and personalization"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d00f455-f1c1-4f08-8b80-9aa4fcbc5ec0', $q$overview$q$, $q$What is Meilisearch?$q$, 2, ARRAY[$q$Meilisearch, founded in 2018 and headquartered in Paris, France, is an open-source search engine that positions itself as a unified search and AI retrieval platform.$q$, $q$It supports full-text, semantic, hybrid, and multimodal search, and is available self-hosted for free or through the managed Meilisearch Cloud.$q$]::text[], 0);
