INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$Official SDKs for ten-plus languages including JS, Python, PHP, Ruby, and Go.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$Typesense Cloud removes the need to operate infrastructure yourself.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$Typesense Cloud pricing is usage-based with no published flat starting price.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$Self-hosting requires you to manage servers or clusters yourself.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$Smaller community (25K GitHub stars) than larger incumbents like Algolia or Elasticsearch.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$Is Typesense open source?$q$, $q$Yes, Typesense is open-source and can be self-hosted via Docker, native binaries, or RPM/DEB packages.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$Does Typesense support vector search?$q$, $q$Yes, it supports vector and semantic search alongside traditional keyword search.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$Can I run Typesense without paying?$q$, $q$Yes, self-hosting is free; Typesense Cloud is a paid, usage-based managed option.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$What languages have official Typesense SDKs?$q$, $q$JavaScript, Go, PHP, Clojure, Swift, Ruby, Python, Dart, .NET, and Java.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$Site & app search$q$, $q$Add typo-tolerant, faceted search to websites, e-commerce catalogs, and apps.$q$, $q$Web/app developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$AI/RAG retrieval$q$, $q$Use built-in vector search to power retrieval-augmented generation pipelines.$q$, $q$AI engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$Multi-tenant SaaS search$q$, $q$Isolate search per customer using multi-tenant API keys.$q$, $q$SaaS platform teams$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$overview$q$, $q$What is Typesense?$q$, 2, ARRAY[$q$Typesense is an open-source search engine that adds typo tolerance, faceting, geo-search, and built-in vector/semantic search to keyword search.$q$, $q$It can be self-hosted via Docker or native binaries, or run as a managed service through Typesense Cloud, which bills based on cluster resources rather than record count.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('09b08922-47a6-4af9-bab1-b845aa9a15c7', $q$who-its-for$q$, $q$Who Typesense is for$q$, 2, ARRAY[$q$Typesense suits developers who want an Algolia-like search experience without proprietary lock-in, including teams building e-commerce search, documentation search, or AI retrieval features.$q$]::text[], 1);
