INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1da597ed-cb15-440d-b621-139ce7ffa976', $q$The Elevate enterprise tier requires an annual contract with custom pricing.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1da597ed-cb15-440d-b621-139ce7ffa976', $q$Pricing is usage-based, so costs scale with request and record volume rather than a flat fee.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1da597ed-cb15-440d-b621-139ce7ffa976', $q$Does Algolia have a free plan?$q$, $q$Yes, the Build plan is free and includes 10K search requests/month and 1M records.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1da597ed-cb15-440d-b621-139ce7ffa976', $q$Does Algolia support AI/semantic search?$q$, $q$Yes, AI capabilities like NeuralSearch and Ask AI are available starting on the Grow Plus plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1da597ed-cb15-440d-b621-139ce7ffa976', $q$What compliance certifications does Algolia hold?$q$, $q$SOC 2 Type 2, ISO 27001, GDPR, and CCPA, among others.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1da597ed-cb15-440d-b621-139ce7ffa976', $q$Is there a free trial for enterprise features?$q$, $q$The Elevate enterprise tier requires an annual contract with custom pricing rather than a trial.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1da597ed-cb15-440d-b621-139ce7ffa976', $q$E-commerce product discovery$q$, $q$Power faceted, typo-tolerant product search and merchandising.$q$, $q$E-commerce teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1da597ed-cb15-440d-b621-139ce7ffa976', $q$Enterprise & documentation search$q$, $q$Search internal knowledge bases or docs with AI-assisted retrieval.$q$, $q$Enterprise IT/support teams$q$, 1);
