INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1da597ed-cb15-440d-b621-139ce7ffa976', $q$Grow$q$, $q$$0.50 per 1,000 additional search requests$q$, $q$monthly$q$, $q$["10K search requests/month included","100K records included ($0.40/1K additional)","Keyword search focused","No annual contract required"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1da597ed-cb15-440d-b621-139ce7ffa976', $q$Grow Plus$q$, $q$$1.75 per 1,000 additional search requests$q$, $q$monthly$q$, $q$["Adds NeuralSearch, AI Synonyms, AI Ranking","Advanced personalization","No annual contract required"]$q$::jsonb, 2);
