INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1da597ed-cb15-440d-b621-139ce7ffa976', $q$overview$q$, $q$What is Algolia?$q$, 2, ARRAY[$q$Algolia is an AI-powered search and retrieval platform used by 18,000+ customers to add neural search, personalization, and generative (RAG) experiences to websites and apps.$q$, $q$Beyond core search, it offers Agent Studio for building AI agents and an MCP server for agentic workflows, alongside enterprise-grade security certifications.$q$]::text[], 0);
