INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$who-its-for$q$, $q$Who Pinecone is for$q$, 2, ARRAY[$q$Pinecone suits AI and ML teams building agents, RAG pipelines, or recommendation systems who want a free tier to prototype and predictable paid tiers as usage grows.$q$]::text[], 1);
