INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('276ddeaa-f3f4-4e0c-bba8-924413dbf6cd', $q$Does Qdrant have a free plan?$q$, $q$Yes, a free-forever tier is available for testing and prototypes.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('276ddeaa-f3f4-4e0c-bba8-924413dbf6cd', $q$Is Qdrant open source?$q$, $q$Yes, it can be self-hosted, with 30K+ GitHub stars.$q$, 1);
