INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('276ddeaa-f3f4-4e0c-bba8-924413dbf6cd', $q$Does Qdrant support hybrid search?$q$, $q$Yes, combining dense and sparse vectors including BM25 and SPLADE++.$q$, 3);
