INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('276ddeaa-f3f4-4e0c-bba8-924413dbf6cd', $q$overview$q$, $q$What is Qdrant?$q$, 2, ARRAY[$q$Qdrant is an open-source vector database built in Rust for real-time, production-grade AI retrieval, supporting hybrid search across dense and sparse vectors.$q$, $q$It can be self-hosted or run through Qdrant Cloud, Hybrid Cloud, Private Cloud, or a beta Edge deployment, with a free-forever tier for testing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('276ddeaa-f3f4-4e0c-bba8-924413dbf6cd', $q$who-its-for$q$, $q$Who Qdrant is for$q$, 2, ARRAY[$q$Qdrant fits AI engineers who need fast, filterable vector search and want the flexibility to self-host, use a managed cloud, or deploy in regulated on-prem environments.$q$]::text[], 1);
