INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$overview$q$, $q$What is Milvus?$q$, 2, ARRAY[$q$Milvus is an open-source vector database purpose-built for GenAI applications, using Global Index technology to perform high-speed similarity search at billions-of-vectors scale.$q$, $q$It can run as an embedded library, a standalone server, or a distributed cluster, and is maintained by Zilliz, which also offers a managed Zilliz Cloud version.$q$]::text[], 0);
