INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f8c6456-68f6-4f02-bd51-cf48403d7a42', $q$overview$q$, $q$What is Turso?$q$, 2, ARRAY[$q$Turso is a database platform built on a Rust-based rewrite of SQLite, designed to provision individual databases per user, tenant, or AI agent while adding cloud-native features like branching and replication.$q$, $q$It offers native vector search for AI/RAG workflows and runs as an embedded engine, in the browser via WebAssembly, or through Turso Cloud.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f8c6456-68f6-4f02-bd51-cf48403d7a42', $q$who-its-for$q$, $q$Who Turso is for$q$, 2, ARRAY[$q$Turso fits developers building multi-tenant SaaS or AI agent products who need many isolated SQLite databases with fast branching and a low-cost entry point.$q$]::text[], 1);
