INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Basic$q$, $q$$0$q$, NULL, $q$["1 user","1,000 credits/month","Limited AI access","Pay-as-you-go credits","Community support"]$q$::jsonb, 0);
