INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$overview$q$, $q$What is Parabola?$q$, 2, ARRAY[$q$Parabola is an AI agent platform for operations and finance teams: users describe a messy recurring process in natural language, and Parabola builds a transparent, editable workflow that runs automatically.$q$, $q$Workflows connect to 1,000+ systems and include retry logic, scheduling, and full audit trails.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$who-its-for$q$, $q$Who Parabola is for$q$, 2, ARRAY[$q$It's aimed at ops and finance teams handling recurring, rules-based work like reconciliations, invoice auditing, and PO matching, who want to automate it without writing code or managing a traditional automation tool.$q$]::text[], 1);
