INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca3ed58b-ad38-4b99-ac69-c8732ec128a9', $q$overview$q$, $q$What is Bardeen?$q$, 2, ARRAY[$q$Bardeen is an automation platform focused on go-to-market teams: it scrapes web data, runs AI-powered research and lead qualification, and enriches contact information.$q$, $q$Results sync directly to Google Sheets, Airtable, or Notion, and usage is metered through a monthly credit system.$q$]::text[], 0);
