INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Auto-generated UIs$q$, $q$Interfaces generated automatically from script parameters.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Scheduling & webhooks$q$, $q$Built-in scheduling and auto-generated webhooks for every script or flow.$q$, 4);
