INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Free tier supports up to 50 users, 3 workspaces, and unlimited executions$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Supports 20+ programming languages for scripts rather than a single proprietary language$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Enterprise features (SAML with group sync, priority support, advanced observability) require the paid Enterprise tier starting at $120/month$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Per-worker and per-seat compute pricing on Enterprise can add up for larger teams$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Is Windmill open source?$q$, $q$Yes, it's fully open-source and can be self-hosted on Docker or Kubernetes.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Is there a free plan?$q$, $q$Yes, the free/open-source plan supports up to 50 users and unlimited executions, self-hosted or on Windmill's cloud.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$What languages does Windmill support for scripts?$q$, $q$Python, TypeScript, Go, Bash, PHP, SQL, and 20+ other languages.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$How is Enterprise priced?$q$, $q$It starts at $120/month base, plus per-developer ($20/mo), per-operator ($10/mo), and per-worker ($50/mo) compute pricing.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Internal tool building$q$, $q$Engineering teams build internal apps and admin tools with UIs auto-generated from script parameters.$q$, $q$Platform and internal tools engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Data pipeline orchestration$q$, $q$Teams orchestrate DAG-based data workflows connecting Postgres, Snowflake, Kafka, and other systems.$q$, $q$Data engineering teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Free and Open-Source$q$, $q$$0$q$, NULL, $q$["Unlimited executions","Self-hosted (Fargate/Docker/Kubernetes)","Up to 50 users","Up to 3 workspaces","10 GiB object storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Enterprise$q$, $q$$120/month base$q$, $q$monthly$q$, $q$["Unlimited executions and workspaces","Audit logs","24/7 priority support (3h response)","SAML with group sync","SOC 2 Type II"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$overview$q$, $q$What is Windmill?$q$, 2, ARRAY[$q$Windmill is an open-source, code-first orchestration platform for building scripts, DAG-based workflows, and internal applications from a single interface.$q$, $q$Scripts can be written in Python, TypeScript, Go, Bash, PHP, SQL, and 20+ other languages, with Windmill auto-generating APIs, forms, and webhooks for each one.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$who-its-for$q$, $q$Who Windmill is for$q$, 2, ARRAY[$q$It's aimed at engineering teams that want a code-first alternative to visual-only automation tools, with the option to self-host for free or use the paid Enterprise tier for SSO, audit logs, and priority support.$q$]::text[], 1);
