INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$@flow decorator$q$, $q$Turns existing Python functions into orchestrated workflows without a new framework.$q$, 0);
