INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Flexible deployment$q$, $q$Run on Prefect Cloud, your own VPC, Kubernetes, ECS, or serverless.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Observability dashboard$q$, $q$Unified view of runs, logs, and states across teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Scheduling & automation$q$, $q$Cron and event-driven triggers, automatic backfills, and SLA monitoring.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Open-source core$q$, $q$The Prefect framework is open source (Apache 2.0) with 40,000+ GitHub stars.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Free open-source framework plus a free Hobby tier on Prefect Cloud$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Python-native — adds orchestration via a decorator rather than a new DSL$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$40,000+ GitHub stars indicate a large open-source community$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Detailed pricing for the Starter, Team, and Pro Cloud tiers isn't published$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Hobby tier is capped at 2 users, 1 workspace, and 5 deployments$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Is Prefect free?$q$, $q$The core Prefect framework is open source, and Prefect Cloud has a free Hobby tier (2 users, 1 workspace, 5 deployments, 500 credits/month).$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$What language does Prefect use?$q$, $q$Prefect workflows are written in Python.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Did Prefect acquire Dagster Labs?$q$, $q$The Prefect site states that Prefect acquired Dagster Labs in July 2026.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Is there a free trial for paid plans?$q$, $q$Yes, a free trial for paid Cloud plans is mentioned in the FAQ.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$ML and data pipeline orchestration$q$, $q$Data and ML teams convert existing Python functions into scheduled, retryable, observable pipelines.$q$, $q$Data engineering and ML teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Agent workflow orchestration$q$, $q$Teams use Prefect to add durable execution and observability to AI agent workflows.$q$, $q$AI and agent engineering teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$Hobby$q$, $q$$0$q$, NULL, $q$["2 users","1 workspace","5 deployments","500 serverless credits/month","Community support","7-day run retention"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$overview$q$, $q$What is Prefect?$q$, 2, ARRAY[$q$Prefect is a Python-native workflow orchestration platform: adding a @flow decorator to existing functions gives them retries, state tracking, scheduling, and crash recovery without a new DSL.$q$, $q$It can run on managed Prefect Cloud or within your own infrastructure (VPC, Kubernetes, ECS, or serverless), and the core framework is open source.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d51e95d-ce2a-4513-a287-44c9039f1a17', $q$who-its-for$q$, $q$Who Prefect is for$q$, 2, ARRAY[$q$It's aimed at data engineering and ML teams already working in Python who want durable, observable orchestration without rewriting pipelines in a new framework. In July 2026, Prefect announced it had acquired Dagster Labs.$q$]::text[], 1);
