INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$First-class integrations$q$, $q$Native support for dbt, Snowflake, and Fivetran.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Core orchestration framework is open source and free to self-host$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Native integrations with dbt, Snowflake, and Fivetran cover common modern data stack tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Branch deployments let teams test pipeline changes before they reach production$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Dagster+ (the hosted product) has no permanent free tier — only a 30-day free trial on Solo and Starter plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Starter plan jumps to $1,200/month (effective May 2026), a steep step up from the $120/month Solo plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Prefect announced it acquired Dagster Labs in July 2026, which could affect the product's future roadmap$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Is Dagster free?$q$, $q$The open-source Dagster orchestration framework is free and self-hostable; the hosted Dagster+ product starts at $120/month after a 30-day free trial.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Was Dagster acquired?$q$, $q$Yes — Prefect's site states that Prefect acquired Dagster Labs, the company behind Dagster, in July 2026.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$What data tools does Dagster integrate with?$q$, $q$It lists first-class integrations with dbt, Snowflake, and Fivetran.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Is there a free trial for Dagster+?$q$, $q$Yes, a 30-day free trial is available for the Solo and Starter plans.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Data pipeline orchestration$q$, $q$Data engineering teams model and orchestrate pipelines as assets with built-in lineage and observability.$q$, $q$Data engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Data quality & cost monitoring$q$, $q$Teams use Dagster+'s catalog, quality monitoring, and cost insights to keep data pipelines healthy and within budget.$q$, $q$Data platform teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Solo$q$, $q$$120/month$q$, $q$monthly$q$, $q$["1 user","1 code location","1 deployment","7,500 credits/month included","30-day free trial"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Starter$q$, $q$$1,200/month$q$, $q$monthly$q$, $q$["Up to 3 users","5 code locations","1 deployment","Catalog search","RBAC","30,000 credits/month included","30-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Unlimited code locations/deployments","Cost insights","Advanced security","Audit logs","SAML integration","Premium support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$overview$q$, $q$What is Dagster?$q$, 2, ARRAY[$q$Dagster is a data orchestration platform built around an open-source, asset-based framework, with a hosted commercial product (Dagster+) adding observability, a data catalog, and AI-assisted diagnostics.$q$, $q$It integrates natively with dbt, Snowflake, and Fivetran, and supports hybrid deployment across cloud and on-premises infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$who-its-for$q$, $q$Who Dagster is for$q$, 2, ARRAY[$q$It's built for data engineering teams that want asset-based pipeline orchestration with strong observability, either by self-hosting the open-source framework for free or paying for the hosted Dagster+ platform starting at $120/month.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
