INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Durable Workflows$q$, $q$Business logic is written as code and executed as a Temporal Workflow with automatic state persistence.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Activities with automatic retries$q$, $q$Functions that retry automatically and recover seamlessly from failures.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Built-in state management$q$, $q$The Temporal Service persists application state and provides built-in retries, task queues, signals, and timers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Full execution visibility$q$, $q$Tracks workflow execution history without requiring extensive log analysis.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Replay and recovery$q$, $q$Workflows can be recovered, replayed, or paused at any point in execution.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Multi-language SDKs$q$, $q$Supports Python, Go, TypeScript, Ruby, C#, Java, and PHP.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Open-source with a self-hosted option in addition to managed cloud$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Multi-language SDK support (Python, Go, TypeScript, Ruby, C#, Java, PHP)$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Used in production by large engineering organizations including Uber, DoorDash, and Cloudflare$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Automatic retry and state-recovery logic reduces custom failure-handling code$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Managed Temporal Cloud plans start at $100/month for Essentials, scaling to custom Enterprise pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Requires developers to write workflow code (not a no-code/visual tool)$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Additional usage beyond plan quotas is billed per action and per GB-hour of storage$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Is Temporal open source?$q$, $q$Yes, Temporal is MIT-licensed and open source, and can be self-hosted for free with community support.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$What is Temporal Cloud's starting price?$q$, $q$The Essentials plan starts at $100/month, including 1M actions and 1GB of active storage.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$What programming languages does Temporal support?$q$, $q$Temporal provides SDKs for Python, Go, TypeScript, Ruby, C#, Java, and PHP.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Does Temporal offer free credits?$q$, $q$New Temporal Cloud signups can get $1,000 in free credits.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Long-running business workflows$q$, $q$Orchestrate multi-step processes like order fulfillment that must survive failures and retries.$q$, $q$Backend engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$AI agent orchestration$q$, $q$Coordinate long-running AI agent and pipeline executions with durable state.$q$, $q$AI/ML engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$CI/CD pipelines$q$, $q$Run and track multi-step build and deployment pipelines reliably.$q$, $q$DevOps teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Essentials$q$, $q$$100/month$q$, $q$monthly$q$, $q$["1M actions included","1 GB active storage","40 GB retained storage","99.9% SLA","1 business day P0 support response"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Business$q$, $q$$500/month$q$, $q$monthly$q$, $q$["2.5M actions included","2.5 GB active storage","100 GB retained storage","SAML SSO and SCIM add-on","2 business hour P0 support response"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Enterprise$q$, $q$Contact sales$q$, NULL, $q$["10M actions included","10 GB active storage","400 GB retained storage","24/7 support with 30-minute P0 response","Design review and worker tuning"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Mission Critical$q$, $q$Contact sales$q$, NULL, $q$["Same inclusions as Enterprise","Optional add-ons"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$overview$q$, $q$What is Temporal?$q$, 2, ARRAY[$q$Temporal is a durable execution platform that lets developers write business logic as ordinary code, called Workflows, while the Temporal Service automatically persists state, handles retries, and manages task queues, signals, and timers.$q$, $q$It is open source (MIT-licensed) and can be self-hosted or run as the managed Temporal Cloud service, with SDKs for Python, Go, TypeScript, Ruby, C#, Java, and PHP.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$who-its-for$q$, $q$Who Temporal is for$q$, 2, ARRAY[$q$Temporal is built for engineering teams that need reliable execution of long-running or multi-step processes, such as order fulfillment, CI/CD pipelines, and AI agent orchestration, without writing custom failure-recovery logic.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
