INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Does Process Street offer a free trial?$q$, $q$Yes, the Pro plan includes a 14-day free trial with no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$What compliance standards does Process Street support?$q$, $q$It supports policy and document control for standards including ISO 9001, SOC 2, SOX, and FDA requirements.$q$, 1);
