INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$who-its-for$q$, $q$Who Process Street is for$q$, 2, ARRAY[$q$It serves operations and compliance teams in regulated sectors such as financial services, healthcare, and manufacturing that need to standardize and document repeatable processes.$q$]::text[], 1);
