INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$What was Kissflow originally called?$q$, $q$Kissflow began as Orangescape, founded in 2003, before launching the Kissflow SaaS product in 2012.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Is Kissflow pricing public?$q$, $q$No, pricing is enterprise-focused and requires a consultation with the sales team.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$What languages does Kissflow support?$q$, $q$The platform is available in English, German, French, Spanish, and Italian.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Does Kissflow use AI?$q$, $q$Yes, Kissflow AI can generate complete apps or app building blocks from a prompt.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Enterprise app development$q$, $q$Build custom business applications without a full engineering team.$q$, $q$IT leaders and citizen developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Process automation$q$, $q$Digitize and automate multi-step business workflows.$q$, $q$Process owners$q$, 1);
