INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$overview$q$, $q$What is Kissflow?$q$, 2, ARRAY[$q$Kissflow is a low-code/no-code platform that lets business users and IT teams build applications, workflows, forms, portals, and boards, with an AI layer that can generate apps or components from a prompt.$q$, $q$The company traces its roots to Orangescape, founded in 2003, before launching Kissflow as a SaaS product in 2012.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$who-its-for$q$, $q$Who Kissflow is for$q$, 2, ARRAY[$q$Kissflow targets enterprise IT leaders, process owners, and citizen developers across industries such as banking, healthcare, retail, and manufacturing who need governed, scalable app development.$q$]::text[], 1);
