INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('443eb7f9-9f62-4c2d-9263-264fcc76d4ee', $q$Layout and feature editing via AI$q$, $q$The AI can redesign layouts, add features, and restructure entire applications on request.$q$, 1);
