INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('443eb7f9-9f62-4c2d-9263-264fcc76d4ee', $q$How much does Stacker cost?$q$, $q$The Standard plan starts at $50/month for 250 credits, with higher credit tiers available up to $2,000/month.$q$, 0);
