INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('443eb7f9-9f62-4c2d-9263-264fcc76d4ee', $q$What is Stacker's AI builder?$q$, $q$Stacker's AI builder lets users describe what they need in natural language and generates a functional no-code application, including redesigning layouts and adding features on request.$q$, 3);
