INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('443eb7f9-9f62-4c2d-9263-264fcc76d4ee', $q$overview$q$, $q$What is Stacker?$q$, 2, ARRAY[$q$Stacker is a no-code application platform where users describe the app they need in natural language and its AI builder generates a functional tool, which can then be edited visually.$q$, $q$Beneath the AI layer is a traditional no-code platform designed to support business-critical applications, with over 2,000 integrations and white-labeled customer portals.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('443eb7f9-9f62-4c2d-9263-264fcc76d4ee', $q$who-its-for$q$, $q$Who Stacker is for$q$, 2, ARRAY[$q$Stacker is designed for non-technical business users who need custom internal tools, CRMs, or client portals without hiring developers.$q$]::text[], 1);
