INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Does WeWeb offer a free plan?$q$, $q$Yes, WeWeb's documentation lists Free tiers among both its Seat plans and Hosting plans.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Can I export code from WeWeb?$q$, $q$Yes, WeWeb outputs production-ready Vue.js Single Page Applications that can be self-hosted.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$When was WeWeb founded?$q$, $q$WeWeb was founded in 2019.$q$, 2);
