INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Internal tools and client apps$q$, $q$Build internal or client-facing web apps with exportable, self-hostable code.$q$, $q$Agencies and enterprise teams$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$overview$q$, $q$What is WeWeb?$q$, 2, ARRAY[$q$WeWeb, founded in 2019 in Paris, is a no-code visual development platform that can generate full web applications from AI prompts and lets users refine them with a drag-and-drop editor.$q$, $q$Unlike many no-code tools, WeWeb exports production-ready Vue.js code that can be self-hosted, and it connects to backends like Airtable, Xano, and Supabase.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$who-its-for$q$, $q$Who WeWeb is for$q$, 2, ARRAY[$q$WeWeb serves founders building MVPs as well as larger organizations and agencies that need custom web apps with code ownership and self-hosting options.$q$]::text[], 1);
