INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$AI-driven build engine$q$, $q$Uses LLM technology to generate real React Native code from the design.$q$, 1);
