INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$Full-service builds (Bravo To Go) cost a flat €999, a significant jump from the subscription plans$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$What does Bravo Studio do?$q$, $q$It converts Figma design files into native React Native mobile apps for iOS and Android using an AI-driven build engine.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$Is there a free plan?$q$, $q$Yes, the Learn plan is free forever and supports unlimited app projects up to 15 screens each.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$Does Bravo Studio offer a free trial of paid features?$q$, $q$Yes, the Solo plan trial gives full access, including Bravo MCP, with no credit card required.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$Can Bravo Studio connect to a backend?$q$, $q$Yes, it supports Convex, REST, and GraphQL data sources.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$What is Bravo MCP?$q$, $q$It's an AI-native builder that lets you build apps from Claude, Cursor, or ChatGPT via the Model Context Protocol, included on the Solo plan.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$Turning a Figma prototype into a real app$q$, $q$Designers can ship their own Figma work as a functioning native app without hiring a developer.$q$, $q$Product designers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$Fast MVP for a mobile startup$q$, $q$Solo founders can validate an app idea by building a real, store-ready app in days.$q$, $q$Solo founders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$Agency client delivery$q$, $q$Agencies use Bravo To Go's concierge build for a fast, done-for-you app delivery.$q$, $q$Agencies$q$, 2);
