INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$Solo$q$, $q$$22/month$q$, $q$monthly$q$, $q$["Up to 30 screens per app","Stripe, OAuth, Firebase, deep links","Unlimited app builds for stores","Bravo MCP included","Convex backend access","Realtime sync from Figma"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$overview$q$, $q$What is Bravo Studio?$q$, 2, ARRAY[$q$Bravo Studio is a no-code mobile app platform that converts Figma design files into real native iOS and Android apps, using an AI-driven build engine to generate React Native code rather than a proprietary wrapper.$q$, $q$It keeps the design file as the source of truth, offers live device previews before publishing, and can connect apps to Convex, REST, or GraphQL backends.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a22cd72-a223-425f-872a-827407f67bb9', $q$who-its-for$q$, $q$Who Bravo Studio is for$q$, 2, ARRAY[$q$It suits product designers who want to ship their own Figma work, solo founders and small teams validating a mobile MVP, and agencies that need to deliver client apps quickly.$q$]::text[], 1);
