INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Now operates as a beehiiv-owned product rather than an independent company$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Is Typedream free to use?$q$, $q$Yes, there's a free plan limited to one page with a 5% transaction fee, plus paid Launch and Grow plans.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Can I sell digital products with Typedream?$q$, $q$Yes, you can sell ebooks, courses, templates, files, and services directly from your site.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Does Typedream include a blog?$q$, $q$Yes, paid plans include CMS-backed blog collections — one on Launch, unlimited on Grow.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Is Typedream still active?$q$, $q$Yes, it was acquired by beehiiv in June 2024 and continues to operate under the Typedream name.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Is there a refund guarantee?$q$, $q$Yes, paid plans come with a 14-day money-back guarantee.$q$, 4);
