INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Is Webnode free?$q$, $q$Yes, Webnode offers a free plan for building and hosting a website indefinitely; premium plans unlock custom domains, more bandwidth, and branding removal.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Does Webnode use AI?$q$, $q$Yes, its AI website generator can create content, edit pages, and build a site from a prompt.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Can I take bookings and invoice clients on Webnode?$q$, $q$Yes, it includes online booking and invoice creation with payment processing.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$How many languages does Webnode support?$q$, $q$The platform advertises support for 25+ languages, including English, Spanish, French, German, Chinese, and Japanese.$q$, 4);
