INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$overview$q$, $q$What is Webnode?$q$, 2, ARRAY[$q$Webnode, founded in 2008, is an AI-assisted website builder aimed at small businesses, contractors, and freelancers, with an AI generator that creates and edits site content from a prompt.$q$, $q$It includes online booking, invoicing and payments, SEO tools, and support for 25+ interface languages, with a free plan available indefinitely alongside premium tiers.$q$]::text[], 0);
