INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa13d6c0-d32a-426d-805b-8124f40390e4', $q$Click-to-edit visual editor$q$, $q$Click any element on the page to edit it directly and publish instantly, with no code or design experience required.$q$, 0);
