INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('aa13d6c0-d32a-426d-805b-8124f40390e4', $q$Does Strikingly support e-commerce?$q$, $q$Yes, through the built-in Simple Store, which connects to PayPal or Stripe and supports coupons, shipping, and digital goods.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('aa13d6c0-d32a-426d-805b-8124f40390e4', $q$Do I need coding skills to use Strikingly?$q$, $q$No, Strikingly is a no-code, click-to-edit builder aimed at people with no design or development background.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('aa13d6c0-d32a-426d-805b-8124f40390e4', $q$Is there a mobile app?$q$, $q$Yes, Strikingly offers an iPhone app for building and editing sites on the go.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('aa13d6c0-d32a-426d-805b-8124f40390e4', $q$Does Strikingly include a blog?$q$, $q$Yes, the Simple Blog feature is built into the editor and gives each post its own page.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa13d6c0-d32a-426d-805b-8124f40390e4', $q$One-page portfolios and landing pages$q$, $q$Creatives and freelancers use Strikingly's templates to launch a mobile-optimized site in under 30 minutes.$q$, $q$Solo entrepreneurs and creatives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa13d6c0-d32a-426d-805b-8124f40390e4', $q$Small online stores$q$, $q$Businesses sell a single product or a full catalog using the built-in Simple Store with PayPal/Stripe checkout.$q$, $q$Small business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa13d6c0-d32a-426d-805b-8124f40390e4', $q$Blogging and audience building$q$, $q$Writers publish updates through the Simple Blog and grow an audience with newsletters and sign-up forms.$q$, $q$Bloggers and content creators$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa13d6c0-d32a-426d-805b-8124f40390e4', $q$overview$q$, $q$What is Strikingly?$q$, 2, ARRAY[$q$Strikingly is a website builder built around a click-to-edit interface: users click directly on any element of a template to change it, without touching code or a separate design tool.$q$, $q$Beyond the site editor, it bundles a store (Simple Store), a blog (Simple Blog), sign-up and contact forms, membership gating, and free built-in analytics and HTTPS on every published site.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa13d6c0-d32a-426d-805b-8124f40390e4', $q$who-its-for$q$, $q$Who Strikingly is for$q$, 2, ARRAY[$q$It's aimed at entrepreneurs, creatives, and small businesses who want a simple, mobile-optimized site or one-page store without hiring a developer or designer.$q$]::text[], 1);
