INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Free-forever core plan$q$, $q$The base plan is free indefinitely, with no credit card required to sign up, and includes hosting and the editor.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Guided website editor$q$, $q$A structured, wizard-style editor where users upload content into pre-built layouts rather than a traditional drag-and-drop canvas.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Built-in SEO tools$q$, $q$SEO settings are built into the editor to help pages be indexed and found in search engines.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Free hosting on CDN infrastructure$q$, $q$Sites are hosted on globally distributed CDN servers to reduce load time for visitors.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Online store$q$, $q$Users can create an online store and sell products globally directly from their site.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Custom domain connection$q$, $q$A custom domain can be connected on a paid plan starting as low as $10.8/month on an annual, prepaid plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Royalty-free image bank$q$, $q$An integrated image bank with royalty-free photos is available for use in site design.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$24/7 live chat support$q$, $q$Live chat support is available at any time to help with building and managing the site.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Genuinely free core plan with no credit card required and no time limit$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Built-in SEO tools and CDN-based free hosting included from the start$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$24/7 live chat support plus a 14-day money-back guarantee on paid plans$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$No limit on the number of websites per account$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Custom domain and full e-commerce features require a paid upgrade$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Editor is more template/wizard-driven than a fully flexible drag-and-drop builder$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Sites cannot be downloaded — SITE123 is a closed, proprietary hosting platform$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Is SITE123 really free?$q$, $q$Yes, the product is offered at no cost, including hosting and the full editor, with no payment or trial commitment required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$How much does a custom domain cost?$q$, $q$Connecting a custom domain starts as low as $10.8/month if paid upfront on an annual plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$How many websites can I create?$q$, $q$There is no limit — a single account can create and manage multiple websites.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Do I need design skills to use SITE123?$q$, $q$No, users upload content and pick from ready-made layouts rather than designing from scratch.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$First business website$q$, $q$Small businesses use the guided editor to get a site online in under an hour without design help.$q$, $q$Small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Basic online store$q$, $q$Sellers set up products and start selling online using the built-in store tools.$q$, $q$Solo entrepreneurs and online sellers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Personal or portfolio sites$q$, $q$Non-technical individuals build a free personal site or portfolio using pre-made layouts.$q$, $q$Non-technical individuals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Free$q$, $q$$0$q$, $q$monthly$q$, $q$["250 MB storage","250 MB bandwidth","SITE123 subdomain"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Premium$q$, $q$From ~$10.8/month (annual)$q$, $q$annual$q$, $q$["Free domain for 1 year","3GB storage","3GB bandwidth","Removes the SITE123 floating tag","Connect your own domain","Online store"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$overview$q$, $q$What is SITE123?$q$, 2, ARRAY[$q$SITE123 is a website builder centered on a guided, wizard-style editor: rather than free-form drag-and-drop, users select a website type and upload their own content into ready-made layouts.$q$, $q$The core plan is free indefinitely with built-in hosting, SEO tools, and support for an online store, while a custom domain and extra storage/bandwidth are paid upgrades.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$who-its-for$q$, $q$Who SITE123 is for$q$, 2, ARRAY[$q$It's aimed at non-technical users and small businesses who want the fastest possible path to a working website without design or coding skills.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Two editors: Website Builder and Creator$q$, $q$A simple no-code website/store builder plus a Creator editor with coding features for custom navigation, stores, and design elements.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Online Store Builder$q$, $q$A dedicated builder for setting up an online store, separate from the general website builder.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Online booking$q$, $q$Customers can take appointments directly through the website via built-in booking tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Smart forms$q$, $q$Contact forms can be created for any occasion directly in the editor.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Business listings (Jimdo Local)$q$, $q$Manages business listings on Google, Facebook, and other platforms from one place.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Social selling integration$q$, $q$Products and content can be promoted and sold directly on Facebook and Instagram.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Warning-proof legal texts$q$, $q$Generates privacy policy and terms text intended to meet legal disclosure requirements.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Long operating history — in business since 2007 with over 32 million Jimdo websites created$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Offers both a simple editor and a code-customizable Creator editor for teams that want more control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Built-in tools for bookings, forms, and legal pages beyond basic site design$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Free plan available, with the option to upgrade at any time$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$No customer service phone hotline — support is via help center, live chat, or email only$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Paying month-to-month costs more than committing to a 12- or 24-month term$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Choosing between the Website Builder and Creator editors upfront matters, since their feature sets differ$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Can I start free and upgrade later?$q$, $q$Yes, you can start with a free website and upgrade to a paid plan at any time from the site dashboard.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Can I connect my own domain?$q$, $q$Yes, premium plans support transferring an existing domain to Jimdo or connecting it while keeping it registered elsewhere.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$How do I pay for a plan?$q$, $q$You can pay monthly, or save money by paying upfront for a 12- or 24-month term.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Can I cancel my contract?$q$, $q$Consumers get a 14-day right of withdrawal where a statutory right applies; this does not apply to business accounts.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Local business websites$q$, $q$Restaurants, coaches, and practices use Jimdo to combine a simple site with online booking and business listings.$q$, $q$Local businesses and solopreneurs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Small online stores$q$, $q$Sellers use the Online Store Builder together with Facebook/Instagram selling integration.$q$, $q$Small online retailers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Custom-coded sites$q$, $q$Teams that need more design control use the Creator editor to hand-code navigation and layout.$q$, $q$Developers and agencies$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$overview$q$, $q$What is Jimdo?$q$, 2, ARRAY[$q$Jimdo is a German website and online store builder, in operation since 2007, that offers two distinct editors: a simple, guided Website/Store Builder and a more advanced Creator editor with coding features.$q$, $q$Beyond page design, it includes booking tools, smart forms, business listing management for Google and Facebook, and legal-text generation for privacy policies and terms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$who-its-for$q$, $q$Who Jimdo is for$q$, 2, ARRAY[$q$It suits local businesses and solopreneurs who want a fast, low-maintenance site or store, as well as developers who want the option to hand-code parts of the site through the Creator editor.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Free publishing platform$q$, $q$Writers can start a publication with no upfront platform fee and no contract to sign.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Built-in paid subscriptions$q$, $q$Writers set a subscription price and readers can pay directly through Substack; the writer keeps 90% of that revenue.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Built-in reader network$q$, $q$More than half of new subscribers come from Substack's built-in network and recommendations rather than outside promotion.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Multi-format publishing$q$, $q$Supports written posts as well as podcasts, video, and live video, not just text newsletters.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Full ownership of list and payments$q$, $q$Writers retain ownership of their intellectual property, mailing list, and subscriber payments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Substack app$q$, $q$A dedicated app is available for reading and managing publications.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$No cost to start publishing or to launch a paid subscription business$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Large existing reader network that surfaces new subscribers through recommendations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Writers keep full ownership of their subscriber list, content, and payouts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Supports podcasts and video in addition to written newsletters$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Substack takes a 10% cut of paid subscription revenue, on top of separate payment-processing fees$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Built primarily around newsletter/post publishing rather than general-purpose website design$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Discovery relies partly on Substack's own network, meaning growth is tied to the platform$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Is Substack free to use?$q$, $q$Yes, it's free to start and free to leave, with no upfront platform fee, tiers, or contract.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$How does Substack make money?$q$, $q$It takes 10% of a writer's paid subscription revenue; the remaining 90% goes to the writer.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Can I publish more than text newsletters?$q$, $q$Yes, Substack supports podcasts, video, and live video alongside written posts.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Do I own my subscriber list?$q$, $q$Yes, writers retain ownership of their intellectual property, mailing list, and subscriber payments.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Paid newsletters$q$, $q$Independent writers and journalists monetize their writing directly through reader subscriptions.$q$, $q$Independent writers and journalists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Paid podcasts$q$, $q$Podcasters use Substack's subscription tools to charge for exclusive episodes.$q$, $q$Podcast creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$Niche expertise publications$q$, $q$Finance writers, food writers, and other subject-matter experts build a direct paying audience.$q$, $q$Subject-matter experts and creators$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$overview$q$, $q$What is Substack?$q$, 2, ARRAY[$q$Substack is a publishing platform where writers and creators distribute newsletters, podcasts, and video, with built-in tools for charging readers a subscription fee.$q$, $q$It's free to start, and Substack's revenue comes from taking a 10% cut of paid subscription revenue rather than charging a platform subscription fee.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', $q$who-its-for$q$, $q$Who Substack is for$q$, 2, ARRAY[$q$It's aimed at independent writers, journalists, podcasters, and niche experts who want to build a direct, paid relationship with their audience without giving up ownership of their list or content.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d9c7050-c8fc-42d3-9a25-ef88330023f2', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Competitor sales-cycle monitoring$q$, $q$Tracks up to 3-5 named competitors and surfaces the specific contacts actively talking to them, with a confidence score.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Daily signal delivery$q$, $q$Delivers signals daily to Salesforce, HubSpot, Slack, Apollo, Outreach, Clay, or a spreadsheet, with a recommended outreach play attached.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Fast time-to-value$q$, $q$First signals arrive within 10 days, with no implementation project required.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Native CRM and outreach integrations$q$, $q$Integrates natively with Salesforce, HubSpot, Gong, Fathom, Circleback, Google Sheets, and Zapier.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$MCP integration with ChatGPT and Claude$q$, $q$Connects via Model Context Protocol so AI assistants can query Letterdrop data and take actions inside the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$SOC 2 compliant data handling$q$, $q$Customer data is encrypted in transit and at rest, and is not used to train Letterdrop's models.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Surfaces named contacts in live competitor sales cycles, not just anonymous account-level research signals$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Delivers signals directly into existing CRM and outreach tools without a new system of record$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$First signals arrive within 10 days with no implementation project$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$SOC 2 compliant and does not use customer data to train models$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$No public self-serve pricing — plans require a demo or sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Best suited to companies with 50+ employees and an established outbound motion$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Stated competitor-signal accuracy is around 30% on average, so not every surfaced contact converts$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$What does Letterdrop do?$q$, $q$It identifies contacts who are actively starting sales cycles with your competitors, tracking public signals to surface live conversations before a vendor is chosen.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$How is Letterdrop different from 6sense or Bombora?$q$, $q$6sense and Bombora track account-level content research; Letterdrop tracks contacts in live conversations forming with specific named competitors.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$What does Letterdrop integrate with?$q$, $q$Salesforce, HubSpot, Slack, Apollo.io, Outreach, Clay, Gong, Fathom, Circleback, Google Sheets, and Zapier, plus ChatGPT and Claude via MCP.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$How accurate is Letterdrop's competitor monitoring?$q$, $q$It identifies contacts at roughly 30% accuracy on average for active competitor sales cycles, and up to about 1 in 2 in some verticals.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Intercepting competitor deals$q$, $q$Sales-led B2B companies use Letterdrop to reach named contacts before a competitor closes the deal.$q$, $q$VPs of Sales and RevOps leaders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Outbound signal enrichment$q$, $q$Outbound agencies and Clay power-users layer Letterdrop's signals on top of enrichment workflows.$q$, $q$Outbound agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Founder-led GTM$q$, $q$Early-stage startups use Letterdrop to activate founders online and generate inbound demos.$q$, $q$Early-stage startup founders$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$overview$q$, $q$What is Letterdrop?$q$, 2, ARRAY[$q$Letterdrop is a competitor-monitoring and pipeline-intelligence platform for B2B sales teams. It identifies specific contacts who are actively starting sales cycles with a company's chosen competitors, rather than showing account-level research interest.$q$, $q$Signals are delivered daily into Salesforce, HubSpot, Slack, Apollo, Outreach, Clay, or a spreadsheet, each with a confidence score and a recommended outreach play, and the platform also connects to ChatGPT and Claude via MCP.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$who-its-for$q$, $q$Who Letterdrop is for$q$, 2, ARRAY[$q$It's built for sales-led companies with at least 50 employees and a repeatable outbound motion, including VPs of Sales, demand gen leaders, outbound agencies, and Clay power-users.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Content modeling$q$, $q$Structure content once and reuse it across websites, ecommerce, and mobile apps.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Developer tooling$q$, $q$APIs, SDKs, and webhooks with official integrations for Angular, Django, Laravel, Next.js, and React.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Workflow and collaboration$q$, $q$User roles and approval flows for streamlining content publishing across a team.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Multisite and multi-language support$q$, $q$Manage multiple brands, regions, and languages from a single CMS instance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Built-in SEO fields$q$, $q$SEO metadata and fast-loading HTML delivery are built into content pages.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$AI Assistant$q$, $q$AI-powered content blocks and suggestions to speed up content creation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Media and asset management$q$, $q$Centralized media library with drag-and-drop uploads and edits.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Free plan with no credit card required, plus a 14-day free trial on every paid plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Official SDKs/integrations for React, Vue, Next.js, Angular, Django, and Laravel$q$, 1);
