INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Usage is tightly metered — API calls, bandwidth, pages, blog posts, and assets all have plan-specific caps$q$, 0);
