INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Do I need a credit card for the Free plan?$q$, $q$No, the Free plan gives full access to core features with no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$What's included in the Free plan?$q$, $q$Unlimited users and components, 50K API calls/month, 100GB bandwidth/month, up to 5 pages, 50 blog posts, 50 collections, and 500 assets.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Does ButterCMS offer a free trial on paid plans?$q$, $q$Yes, every paid plan includes a 14-day free trial.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Which frameworks does ButterCMS officially support?$q$, $q$Angular, Django, Laravel, Next.js, and React have official integrations and quickstart guides.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Adding a CMS layer to an app$q$, $q$Developers add ButterCMS as a headless content layer to an existing product using its APIs and SDKs.$q$, $q$Developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Marketing-led publishing$q$, $q$Marketers publish and update landing pages and blog content without filing developer tickets.$q$, $q$Marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Multi-brand content management$q$, $q$Teams manage content across multiple sites, brands, or languages from one CMS.$q$, $q$Multi-brand or multi-region teams$q$, 2);
