INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Custom API calls, bandwidth, pages, collections, assets, roles, and locales","Workflows","Enterprise support","Customer Success Manager","SLA","Onboarding and migration support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$overview$q$, $q$What is ButterCMS?$q$, 2, ARRAY[$q$ButterCMS is an API-first headless CMS designed to let marketers publish content quickly while developers integrate it into React, Vue, Next.js, Angular, Django, or Laravel projects using official SDKs.$q$, $q$It includes workflow tools (roles and approval flows), multisite/multi-language support, built-in SEO fields, and an AI Assistant for content creation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$who-its-for$q$, $q$Who ButterCMS is for$q$, 2, ARRAY[$q$It suits developers who want a hosted, API-driven CMS without building one from scratch, and marketers who need to publish and update content without waiting on engineering.$q$]::text[], 1);
