INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Free plan quotas$q$, $q$The Free plan includes 100K API calls/month and 50GB asset bandwidth/month, with no overages allowed.$q$, 6);
