INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$What is Palmata?$q$, $q$Palmata is Contentful's newer product for understanding and improving how an organization is represented in AI discovery and search.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Does Contentful support personalization?$q$, $q$Yes, Contentful Personalization lets teams create tailored experiences and run experimentation.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$Composable digital experience platform$q$, $q$Enterprises use Contentful to unify content delivery across web, personalization, and analytics.$q$, $q$Enterprise digital teams$q$, 0);
