INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$overview$q$, $q$What is Contentful?$q$, 2, ARRAY[$q$Contentful is a composable digital experience platform that combines a headless CMS with personalization, AI-driven content automation (AI Actions), and analytics tools like Studio.$q$, $q$It also offers Palmata, a newer product focused on how organizations are represented in AI-powered discovery and search.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dca1fcb2-9238-4516-ba95-c8cb62820764', $q$who-its-for$q$, $q$Who Contentful is for$q$, 2, ARRAY[$q$It's aimed at enterprise and mid-market teams that need to manage content across many channels and want personalization and analytics built into the same platform, alongside developers building headless front-ends.$q$]::text[], 1);
