INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Does Storyblok have a free plan?$q$, $q$Yes, the Starter plan is free and includes 1 space, 1 user seat, and 100GB traffic per month.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Is there a free trial?$q$, $q$Yes, a 45-day free trial of the Growth Plus plan is offered before committing to a paid plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$When was Storyblok founded?$q$, $q$Storyblok was started in 2017 in Austria by founders Dominik and Alexander.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Does Storyblok support AI or agent workflows?$q$, $q$Yes, it offers an MCP Server and includes AI credits for AI-assisted content features.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Visual content editing$q$, $q$Marketing teams use the visual editor and Global Components to build and rearrange pages without code.$q$, $q$Marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Headless site development$q$, $q$Developers build front-ends with Next.js, Nuxt, or Astro against Storyblok's APIs.$q$, $q$Developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Multi-brand enterprise content$q$, $q$Enterprises manage content across multiple brands, regions, and locales.$q$, $q$Enterprise content teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Starter$q$, $q$Free$q$, $q$monthly$q$, $q$["1 space","1 user seat (up to 2 at $15/mo each)","100GB traffic/month","100k API requests/month","2 locales","25k AI credits"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Growth$q$, $q$$99.00/mo ($90.75/mo billed annually)$q$, $q$monthly$q$, $q$["5 user seats (up to 10 at $15/mo each)","400GB traffic/month (up to 1TB)","1M API requests/month (up to 5M)","2 locales included","97% uptime SLA","100k AI credits/month","Shopify integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Growth Plus$q$, $q$$349.00/mo ($319.91/mo billed annually)$q$, $q$monthly$q$, $q$["15 user seats (up to 20 at $15/mo each)","1TB traffic/month (up to 2TB)","4M API requests/month (up to 15M)","10 locales included","97% uptime SLA","200k AI credits/month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$Premium & Elite$q$, $q$Custom$q$, NULL, $q$["Custom users/seats","AI SEO","Custom roles and workflows","GraphQL","Release management","SSO","SCIM","99.9% uptime SLA"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$overview$q$, $q$What is Storyblok?$q$, 2, ARRAY[$q$Storyblok is a headless CMS founded in 2017 in Austria, built around a visual editor and reusable component blocks ('Global Components') on top of an API-first architecture (GraphQL, REST, and Management APIs).$q$, $q$It offers a free Starter plan, a self-serve Growth and Growth Plus tier with published pricing, and custom Premium/Elite tiers for enterprise needs like SSO and custom SLAs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e2b87a4-c5be-4f23-acc9-dd611b9c5856', $q$who-its-for$q$, $q$Who Storyblok is for$q$, 2, ARRAY[$q$It's built for teams where both developers and marketers need to work in the same CMS — developers building reusable components, marketers assembling pages visually without code.$q$]::text[], 1);
