INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Visual Page Builder$q$, $q$A headless CMS where pages are assembled from reusable, brand-approved sections called slices.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Slice Machine$q$, $q$A local developer tool for coding and customizing slices within a normal development workflow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$AI translation$q$, $q$Creates and manages multilingual content while keeping each locale aligned to a master page structure.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$AI landing page builder$q$, $q$A separately priced add-on that uses AI to scale creation of on-brand landing pages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$MCP integration with ChatGPT and Claude$q$, $q$AI assistants can query and edit pages across the site directly through a single prompt.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Built-in SEO/GEO schema support$q$, $q$Pages include schema support aimed at visibility in AI search and Google Search.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Migration API$q$, $q$Included even on the Free plan for moving content into or out of Prismic.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Free plan includes 4M API calls/month and unlimited documents, types, and assets$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Self-serve pricing is fully published from Free through the Platinum tier$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Founded in 2013 with 10,000+ websites built on the platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Native MCP integration lets ChatGPT and Claude make prompt-driven edits across pages$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$User seats are limited on lower tiers — 1 user on Free, 3 on Starter$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$The AI landing page builder is a separate paid add-on, not included in base plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Enterprise features like SSO and a dedicated Customer Success Manager require a custom quote$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Is Prismic free to use?$q$, $q$Yes, the Free plan includes 1 user, 4 million API calls/month, and 100GB of CDN bandwidth/month at no cost.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$How is Prismic priced?$q$, $q$Per repository, billed annually, ranging from Free up to Platinum at $675/month, with Enterprise available on request.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Where is Prismic based?$q$, $q$Prismic's headquarters is in Paris, France.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Does Prismic support AI-assisted editing?$q$, $q$Yes, including AI translation and prompt-driven page updates through its MCP integration with ChatGPT and Claude.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$SEO and ABM landing pages$q$, $q$Marketing teams build landing pages for SEO and account-based marketing at scale using slices.$q$, $q$Marketing teams$q$, 0);
