INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Multi-client site management$q$, $q$Agencies manage multiple client websites from a single platform.$q$, $q$Agencies$q$, 2);
