INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Custom usage quotas","2 development environments","Backups","Custom roles","Customer Success Manager","SSO","Support and uptime SLAs"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$overview$q$, $q$What is Prismic?$q$, 2, ARRAY[$q$Prismic, founded in 2013 in Paris, is a headless CMS and page builder built around reusable content sections called slices, developed locally with a tool called Slice Machine.$q$, $q$It has since added AI features including AI translation, an AI landing page add-on, and an MCP integration that lets ChatGPT and Claude query and edit pages directly through a prompt.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e4d2898-7923-44d2-a2aa-f2138ec31ce4', $q$who-its-for$q$, $q$Who Prismic is for$q$, 2, ARRAY[$q$It's used by marketing teams building SEO and ABM landing pages, developers building reusable page sections, and agencies managing multiple client sites on one platform.$q$]::text[], 1);
