INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$GraphQL Content Delivery API$q$, $q$Content is delivered through a GraphQL-based Content Delivery API alongside a REST Content Management API.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Structured Text editor$q$, $q$A block-based rich text editor for structured, reusable content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Built-in localization$q$, $q$Multi-locale content management is included, with 5 locales on both the Free and Professional plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Modular content modeling$q$, $q$Content is built from reusable, component-based models for dynamic page building.$q$, 3);
