INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Plugin ecosystem$q$, $q$Over 200 plugins are available to expand and customize the CMS.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Cache Tags$q$, $q$Fine-grained cache invalidation for high-performance content delivery.$q$, 6);
