INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Transparent published pricing for both Free and Professional tiers, with clear add-on pricing for overages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Large plugin marketplace (200+) and an active Slack developer community (3,000+ members)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Structured Text and modular content modeling suited to complex, multi-format sites$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Free plan is capped at 300 records, 10GB traffic/month, and 1 collaborator, with no overages allowed$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Higher usage (extra projects, records, bandwidth, API calls) is billed as recurring add-ons on top of the Professional price$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Community-based support only on the Free plan; faster email support requires the paid Professional tier$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Is DatoCMS free?$q$, $q$Yes, there is a free-forever plan with 2 editors, 300 records, and 100k API calls/month, with no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$How much is the paid plan?$q$, $q$The Professional plan starts at €149/month billed annually, or €199/month billed monthly.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$What happens if I exceed the Free plan's limits?$q$, $q$The service stops responding as expected, since no overages are allowed on the Free plan.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Does DatoCMS support multiple languages?$q$, $q$Yes, localization is built in, with 5 locales included on both the Free and Professional plans and additional locales available as an add-on.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Agency client sites$q$, $q$Digital agencies build multilingual client sites and get a discount through DatoCMS's Agency Partner Program.$q$, $q$Digital agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Modern front-end development$q$, $q$Developers build with Next.js, Nuxt, Astro, or SvelteKit against DatoCMS's GraphQL API.$q$, $q$Developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Structured content management$q$, $q$Content teams manage modular, structured content across a website using the Structured Text editor.$q$, $q$Content teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Free$q$, $q$€0/mo$q$, $q$monthly$q$, $q$["2 editors","300 records","10GB traffic/month","100k API calls/month, no overages","200MB file storage","3-day history retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$Professional$q$, $q$€149/mo (billed annually) or €199/mo (monthly)$q$, $q$monthly$q$, $q$["1 project (3 with add-ons)","10 collaborators","100 models","5 locales","100k records","1TB/mo bandwidth","1M CDA API calls/mo","500GB file storage","60-day history retention"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$overview$q$, $q$What is DatoCMS?$q$, 2, ARRAY[$q$DatoCMS is a headless CMS built around a GraphQL Content Delivery API, a Structured Text editor, and built-in localization, aimed at both developers and content teams.$q$, $q$It offers a free-forever plan with published limits (2 editors, 300 records, 100k API calls/month) and a Professional plan starting at €149/month billed annually, with clearly priced add-ons for extra usage.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a7743d6-ac1d-4562-b878-cfc332ab5aeb', $q$who-its-for$q$, $q$Who DatoCMS is for$q$, 2, ARRAY[$q$It's used by developers building with modern frameworks like Next.js, Nuxt, and Astro, as well as digital agencies and content teams managing structured, multilingual content.$q$]::text[], 1);
