INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Is Strapi free?$q$, $q$Yes, the core Strapi CMS is MIT-licensed and free to self-host; Strapi Cloud managed hosting starts at $35/month per project.$q$, 0);
