INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$Can AI agents work with Strapi?$q$, $q$Yes, Strapi MCP (Model Context Protocol) lets AI agents manage content directly.$q$, 3);
