INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$overview$q$, $q$What is Strapi?$q$, 2, ARRAY[$q$Strapi is an open-source, MIT-licensed headless CMS that lets developers define content types and automatically generates REST and GraphQL APIs from them. It can be self-hosted for free or run on Strapi Cloud, a managed hosting option starting at $35/month.$q$, $q$Because it's a real Node.js application, teams can extend Strapi with custom controllers, services, and middleware, and reshape the admin panel to fit their workflow.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9eb13448-c65d-4848-a1d8-3d2a010b723d', $q$who-its-for$q$, $q$Who Strapi is for$q$, 2, ARRAY[$q$Strapi suits development teams that want full control over their content API and infrastructure, from solo developers self-hosting for free to enterprises needing SSO and audit logs on paid tiers.$q$]::text[], 1);
