INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$SSO/SAML, Media Library, and custom retention are Enterprise-only, quote-based features.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$Dedicated support ($799/mo) and extra datasets ($999/dataset/mo) are paid add-ons on top of Growth.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$Free plan datasets are public only; private datasets require the Growth plan.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$Does Sanity have a free plan?$q$, $q$Yes, the Free plan includes 20 seats, 2 public datasets, 10k documents, and 100GB of assets and bandwidth.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$What is GROQ?$q$, $q$Sanity's custom query language for retrieving structured content from the platform.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$What does Content Agent do?$q$, $q$It's an AI-powered feature for transforming source material, auditing content, and preparing changes.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$How much does Sanity cost?$q$, $q$Free, then Growth at $15/seat/month (up to 50 seats), or custom Enterprise pricing.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$Structured, reusable content$q$, $q$Teams model content once and reuse it across web, mobile, and other channels.$q$, $q$Content teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$Multi-channel content delivery$q$, $q$Developers build apps on Next.js, Astro, SvelteKit, and other frameworks using Sanity's APIs.$q$, $q$Developers$q$, 1);
