INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$Free$q$, $q$$0$q$, NULL, $q$["20 seats","2 public datasets","10k documents","100GB assets & bandwidth","2 GROQ webhooks"]$q$::jsonb, 0);
