INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Custom seats/roles","SSO with SAML","Media Library","365-day history","Audit trails","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$overview$q$, $q$What is Sanity?$q$, 2, ARRAY[$q$Sanity is a headless CMS that stores content as structured JSON documents, edited through Sanity Studio, a customizable, real-time collaborative interface. It includes an AI-powered Content Agent for transforming, auditing, and preparing content changes.$q$, $q$The platform offers a free plan for up to 20 seats, a per-seat Growth plan starting at $15/seat/month, and custom Enterprise pricing for advanced governance features.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cfb2973b-621a-4e4a-b368-035048c957fd', $q$who-its-for$q$, $q$Who Sanity is for$q$, 2, ARRAY[$q$Sanity fits content and development teams that need structured, reusable content across multiple channels, from small teams on the free plan to enterprises requiring SSO and custom compliance controls.$q$]::text[], 1);
