INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Is Directus free?$q$, $q$Yes, the Core plan is free to self-host with no credit card required; Directus Cloud hosting is a $99/month add-on.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Do I need to migrate my database to use Directus?$q$, $q$No, Directus connects to your existing database and generates APIs on top of it.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Does Directus support AI agents?$q$, $q$Yes, via a native MCP server plus a built-in AI Assistant for content and translation tasks.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$What is the Open Innovation Grant?$q$, $q$Free full-featured access for organizations under $5M annual revenue and fewer than 50 employees.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Turning legacy databases into APIs$q$, $q$Backend teams expose existing databases as REST/GraphQL APIs without migrating data.$q$, $q$Backend developers$q$, 0);
