INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Core$q$, $q$$0/month$q$, NULL, $q$["3 user seats","25 Collections","5 Flows","AI Assistant","Advanced RBAC","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Team$q$, $q$$499/month (annual) or $599/month (monthly)$q$, $q$monthly$q$, $q$["10 SSO seats","50 Collections","20 Flows","SSO (SAML/OIDC)","Basic support","Cloud hosting included"]$q$::jsonb, 1);
