INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Open Innovation Grant$q$, $q$Free (self-hosted) or $99/month (cloud)$q$, $q$monthly$q$, $q$["Full feature access, no artificial caps","For orgs under $5M revenue and <50 employees"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$overview$q$, $q$What is Directus?$q$, 2, ARRAY[$q$Directus is an open-source backend and headless CMS that connects directly to an existing database and automatically generates REST and GraphQL APIs along with a no-code admin app called Studio.$q$, $q$It's free to self-host as the Core plan, with paid Team ($499-599/month) and custom Enterprise tiers adding SSO, more Flows, and dedicated support.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$who-its-for$q$, $q$Who Directus is for$q$, 2, ARRAY[$q$Directus suits backend developers who want to expose an existing database as an API without migrating data, and organizations that want built-in AI assistance and MCP support for content management.$q$]::text[], 1);
