INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Works with MongoDB, Postgres, or SQLite.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Instant-deploy templates available for Vercel and Cloudflare.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$No public self-serve pricing beyond free self-hosting; Enterprise plan pricing requires a sales demo.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Managed hosting pricing (Vercel/Cloudflare templates) is not disclosed on Payload's own site.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Built specifically for Next.js, so it isn't framework-agnostic like some other headless CMS options.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Payload was acquired by Figma, which could shift its independent product direction over time.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Is Payload free?$q$, $q$Yes, Payload is MIT-licensed and free to self-host; Enterprise support and hosting have separate, undisclosed pricing.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Is Payload built specifically for Next.js?$q$, $q$Yes, it's designed to run natively inside Next.js applications without separate infrastructure.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Who owns Payload?$q$, $q$Payload is now part of Figma, as announced on Figma's blog, and remains open source.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Does Payload support AI features?$q$, $q$Yes, it includes automatic vector embedding and RAG preparation for AI applications.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Embedded CMS for Next.js apps$q$, $q$Developers add a full CMS and admin panel directly inside a Next.js codebase.$q$, $q$Full-stack developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$AI-ready content pipelines$q$, $q$Teams use built-in RAG and vector embedding support to feed content into AI applications.$q$, $q$AI product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Multi-tenant platforms$q$, $q$Organizations build white-labeled, multi-tenant products on Payload's built-in support.$q$, $q$Enterprises$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Self-hosted$q$, $q$Free$q$, NULL, $q$["MIT licensed, open source","Requires Node.js 20.9+","MongoDB, Postgres, or SQLite"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Dedicated support","Unlimited custom domains","White-labeled email service","SSO","Visual editing","Roadmap influence"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$overview$q$, $q$What is Payload CMS?$q$, 2, ARRAY[$q$Payload is an open-source, code-first headless CMS and backend built specifically for Next.js, with an admin panel that's auto-generated from your schema. It's MIT-licensed and free to self-host on MongoDB, Postgres, or SQLite.$q$, $q$Payload is now part of Figma, according to Figma's own announcement, though it remains open source and continues to be actively developed.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('14aeb166-94c7-4343-ba72-b485b767c52b', $q$who-its-for$q$, $q$Who Payload CMS is for$q$, 2, ARRAY[$q$Payload suits Next.js developers who want a CMS and backend embedded directly in their codebase, plus teams building AI-ready content pipelines that need built-in RAG and vector embedding support.$q$]::text[], 1);
