INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Growth plan jumps to $199/month from the free Hobby tier, with no mid-tier option shown.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$SSO, multitenancy, and dedicated infrastructure require custom Enterprise pricing.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Hobby plan is capped at 1,000 entries and 500,000 API calls per month.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Founding year and headquarters are not disclosed on the site.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Is Hygraph free?$q$, $q$Yes, the Hobby plan is free forever, with 3 seats and unlimited asset storage up to certain usage limits.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Does Hygraph support content federation?$q$, $q$Yes, its GraphQL-native architecture can combine multiple data sources without duplicating data.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Is Hygraph SOC 2 certified?$q$, $q$Yes, it has been SOC 2 Type 2 certified since August 2022, and is also ISO 27001 certified.$q$, 2);
