INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Multi-language content delivery$q$, $q$Global marketing teams manage localized content across many locales.$q$, $q$Global marketing teams$q$, 1);
