INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Growth$q$, $q$$199/month$q$, $q$monthly$q$, $q$["3 locales","10 seats","1 remote source connection","14-day version retention","10,000 entries","1,000,000 API calls/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Up to 80 locales","200 seats","SSO","Multitenancy","Dedicated infrastructure","24/7 monitoring"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$overview$q$, $q$What is Hygraph?$q$, 2, ARRAY[$q$Hygraph is a GraphQL-native headless CMS built for managing structured, relational content and federating it from multiple data sources into a single API. It offers a free Hobby plan, a Growth plan starting at $199/month, and custom Enterprise pricing.$q$, $q$Security features include SOC 2 Type 2 and ISO 27001 certification, along with SSO and granular RBAC on higher tiers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$who-its-for$q$, $q$Who Hygraph is for$q$, 2, ARRAY[$q$Hygraph fits enterprises and high-growth companies that need to combine content from multiple systems via GraphQL federation, particularly in regulated industries needing SOC 2/ISO 27001 compliance.$q$]::text[], 1);
