INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Prime$q$, $q$€179/agent/month$q$, $q$monthly$q$, $q$["Everything in Ultimate","SSO","Advanced AI intent detection","Custom user roles","Multiple organizations","Enterprise API limits"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$overview$q$, $q$What is Dixa?$q$, 2, ARRAY[$q$Dixa is a customer service platform for ecommerce brands that unifies phone, email, chat, social, and WhatsApp conversations into one Team Hub, and uses its Mim AI Agent to autonomously resolve routine inquiries such as refunds and order tracking.$q$, $q$Plans start at €89/agent/month for Growth, scaling up to €179/agent/month for Prime, with Mim AI Agent usage billed separately at €0.35 per conversation.$q$]::text[], 0);
