INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Performance figures (e.g. 76% AI resolution, $510M+ saved) are Gladly's own reported case-study claims rather than independently audited results.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Founding year and headquarters are not disclosed on the site.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$How much does Gladly cost?$q$, $q$Pricing isn't published; it requires requesting a demo or contacting sales.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$What is Gladly?$q$, $q$A customer experience AI platform that unifies conversations around a single customer timeline across channels.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$What channels does Gladly support?$q$, $q$Voice, chat, SMS, email, and social media.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Who uses Gladly?$q$, $q$Named customers include Ulta Beauty, Nordstrom, TUMI, UGG, and Crate & Barrel.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Unifying customer conversations across channels$q$, $q$Retail brands replace channel-siloed tickets with one continuous customer timeline.$q$, $q$Retail and ecommerce support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Non-technical AI configuration$q$, $q$Business users adjust AI behavior and brand voice through plain-English Guides.$q$, $q$Customer experience managers$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$overview$q$, $q$What is Gladly?$q$, 2, ARRAY[$q$Gladly is a customer experience AI platform that organizes support around a single, continuous customer timeline rather than per-channel tickets, spanning voice, chat, SMS, email, and social media.$q$, $q$Its AI agent can resolve conversations independently or collaborate with human agents, and business users can configure AI behavior through plain-English "Guides" without engineering support. Pricing is not published and requires contacting Gladly directly.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$who-its-for$q$, $q$Who Gladly is for$q$, 2, ARRAY[$q$Gladly is aimed at retail and consumer brands that want a relationship-focused, single-timeline view of each customer across every support channel, as reflected in its named customers like Ulta Beauty and Nordstrom.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
