INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Cost scales with AI conversation volume, which can be unpredictable as support volume grows.$q$, 1);
