INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$How is Richpanel priced?$q$, $q$$99/seat/month for helpdesk seats plus roughly $0.20 per AI-handled conversation, with a $200/month minimum.$q$, 0);
