INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Cutting support costs with AI$q$, $q$Ecommerce brands offload routine tickets to AI resolution instead of hiring proportionally.$q$, $q$Ecommerce support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Multi-brand support operations$q$, $q$Companies running several storefronts manage support for all of them from one workspace.$q$, $q$Multi-brand retailers$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Usage-based$q$, $q$$99/agent/month + ~$0.20/AI conversation ($200/month minimum)$q$, $q$monthly$q$, $q$["Helpdesk seats billed per agent","AI conversations billed on actual token use","Annual billing saves 17%"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$overview$q$, $q$What is Richpanel?$q$, 2, ARRAY[$q$Richpanel is an AI-native helpdesk built for ecommerce brands, combining a shared inbox with an AI Resolution engine that autonomously handles support tickets across email, chat, Instagram, WhatsApp, SMS, and voice.$q$, $q$Pricing is usage-based: $99/agent/month for helpdesk seats plus roughly $0.20 per AI-handled conversation, with a $200/month minimum and a guarantee that AI resolves at least 50% of tickets within 30 days.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$who-its-for$q$, $q$Who Richpanel is for$q$, 2, ARRAY[$q$Richpanel is aimed at ecommerce brands that want to reduce support headcount growth by automating routine tickets while giving customers a self-service portal for orders, returns, and subscriptions.$q$]::text[], 1);
