INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a3094cf-a8e5-4f7e-b9ed-7fe69416116b', $q$Live chat plus email in one inbox$q$, $q$Ecommerce stores manage all customer messages from a single Intelligent Inbox.$q$, $q$Ecommerce support teams$q$, 0);
